----------------------------------------------------------------------
-- DCS Civil Mission Template - Police (Chase + SWAT)
-- File: 30_CivilPolice.lua  (requires 01_CivilCore.lua)
--
--   CHASE: fugitive car spawned on a "CIVIL Police Point" (pool placed on
--   real city crossroads). Route = local random walk between nearby points
--   with "On Road" waypoints for native road pathfinding.
--   KNOWN ISSUE (verified): "On Road" is buggy across versions (units can
--   stray or get stuck). A watchdog re-tasks a stalled car and falls back
--   to "Off Road" on the second stall.
--   Capture: per-chase "pressure" that rises while a player helicopter is
--   within radius and decays when contact is lost; rates randomized ONCE
--   per chase. 100% = arrest.
--
--   SWAT: board the team at "CIVIL SWAT Base" (squad size fixed at
--   BOARDING, not at insertion), then fast-rope insertion over a
--   "CIVIL SWAT Point" via hover watch + scripted coalition.addGroup
--   (native embark/disembark tasks are AI-to-AI: unusable here).
--   TO TEST in-game: infantry spawn reliability on rooftop meshes.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config
local CP = C.police
local CS = C.swat

----------------------------------------------------------------------
-- CHASE
----------------------------------------------------------------------

CIV.Police = { _chases = {}, _cid = 0 }
local PL = CIV.Police

-- Optional scene dressing (robbery scene at the chase start, standoff at
-- the SWAT objective): same template mechanics as the rescue scenes, same
-- lingering despawn delay after the event ends.
local function spawnPoliceScene(templates, point)
  if not templates or #templates == 0 then return nil end
  local prefix = templates[math.random(#templates)]
  local sp = CIV.offsetPoint(point, math.random(0, 359), 20)
  local gname = CIV.spawnFromTemplate(prefix, sp)
  if not gname then CIV.dbg("No scene template for prefix '" .. prefix .. "'") end
  return gname
end

local function releaseSceneLater(gname)
  if not gname then return end
  CIV.schedule(function() CIV.despawnGroup(gname) end,
    nil, C.rescue.scenes.despawnDelay)
end

local function waypoint(pt, speed, action)
  return { x = pt.point.x, y = pt.point.z, type = "Turning Point",
           action = action or "On Road", speed = speed,
           ETA = 0, ETA_locked = false, speed_locked = true }
end

-- next hops via local random walk (never map-wide jumps)
local function makeHops(fromPt, n, excludeName)
  local hops, current, lastName = {}, fromPt, excludeName
  for _ = 1, n do
    local nearby = CIV.Pool.near(C.zones.policePoints, current.point,
      CP.neighborRadius, lastName)
    if #nearby == 0 then break end
    local nxt = nearby[math.random(#nearby)]
    hops[#hops + 1] = nxt
    lastName = current.name
    current = nxt
  end
  return hops
end

local function assignRoute(chase)
  local g = Group.getByName(chase.gname)
  local u = g and g:getUnit(1)
  if not u then return end
  local p = u:getPoint()
  local points = { { x = p.x, y = p.z, type = "Turning Point",
                     action = chase.roadAction, speed = chase.speed } }
  for _, pt in ipairs(chase.hops) do
    points[#points + 1] = waypoint(pt, chase.speed, chase.roadAction)
  end
  g:getController():setTask({ id = "Mission", params = { route = { points = points } } })
end

-- opts (command center): { point = vec3, severity = 1..10 }. A commanded
-- point snaps to the nearest free crossroad of the pool (the chase needs
-- the road network).
function PL.startChase(opts)
  local n = 0
  for _ in pairs(PL._chases) do n = n + 1 end
  if not (opts and opts.point) and n >= CP.maxChases then return nil end

  local start
  if opts and opts.point then
    local bestDist = 1e12
    for _, pt in ipairs(CIV.Pool.load(C.zones.policePoints)) do
      local d = CIV.dist2D(pt.point, opts.point)
      if d < bestDist and not CIV.Pool._active[pt.name] then
        start, bestDist = pt, d
      end
    end
  else
    start = CIV.Pool.pick(C.zones.policePoints, 800)
  end
  if not start then return nil end

  PL._cid = PL._cid + 1
  -- one severity roll shapes the chase: car speed, pressure rates, convoy
  -- size and score (severity 10 = fast car, slow pressure build, 2 vehicles)
  local sev = (opts and opts.severity)
    and math.max(1, math.min(10, opts.severity))
    or CIV.rollSeverity(CP.severity)
  local cars = sev >= CP.convoySeverity and 2 or 1
  local gname = CIV.spawnGround(start.point, cars, C.templates.fugitive,
    C.fallbackTypes.fugitive, "CIVIL_FUGITIVE")

  local chase = {
    id = PL._cid, gname = gname, startPt = start,
    severity     = sev,
    speed        = CIV.sevLerp(sev, CP.carSpeed.min, CP.carSpeed.max),
    rateUp       = CIV.sevLerp(sev, CP.pressureUp.max, CP.pressureUp.min),
    rateDown     = CIV.sevLerp(sev, CP.pressureDown.min, CP.pressureDown.max),
    pressure     = 0,            -- 0..100, per-chase state
    roadAction   = "On Road",
    stalledSince = nil, rekicks = 0,
    hops = makeHops(start, CP.routeHops, nil),
    lastPos = nil,
  }
  PL._chases[chase.id] = chase
  CIV.Pool.occupy(start)
  chase.sceneGname = spawnPoliceScene(CP.sceneTemplates, start.point)
  chase.zoneMarkId = CIV.drawEventZone(start.area,
    "Police chase #" .. chase.id .. " last report", "chase")
  CIV.schedule(function() assignRoute(chase) end, nil, 2)

  CIV.msgAll("POLICE: fleeing " .. (cars > 1 and "CONVOY" or "vehicle") ..
    " reported near " .. start.name .. " (severity " .. sev .. "/10)" ..
    "\n" .. CIV.coordText(start.point) ..
    "\nLast reported area highlighted on the F10 map." ..
    "\nKeep helicopter contact on the vehicle to build up pressure.", 25)
  CIV.log("Chase #" .. chase.id .. " started at " .. start.name ..
    " severity " .. sev)
  return chase
end

local function closeChase(chase, despawnAfter)
  CIV.Pool.release(chase.startPt)
  CIV.unmark(chase.zoneMarkId)
  releaseSceneLater(chase.sceneGname)
  chase.sceneGname = nil
  PL._chases[chase.id] = nil
  local gname = chase.gname
  CIV.schedule(function() CIV.despawnGroup(gname) end, nil, despawnAfter or 60)
end

-- command center: close a chase without any outcome
function PL.cancel(chase)
  closeChase(chase, 1)
end

-- chase loop: pressure + route extension + "On Road" watchdog
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, chase in pairs(PL._chases) do
    local g = Group.getByName(chase.gname)
    local u = g and g:getUnit(1)
    if not u or not u:isExist() then
      closeChase(chase, 1)
    else
      local p = u:getPoint()

      local contact = false
      CIV.forEachPlayerHelo(function(h)
        if not contact and CIV.dist2D(h:getPoint(), p) <= CP.pressureRadius then
          contact = true
        end
      end)

      -- TRAFFIC WATCH: an airplane orbiting over the fugitive keeps the
      -- pursuit on camera; while the watch holds, helicopter pressure
      -- builds faster and the watcher earns an assist on the arrest
      local TW = CP.trafficWatch
      local watcher = nil
      if TW.enabled then
        CIV.forEachPlayer(function(a, info)
          if watcher or info.category ~= Unit.Category.AIRPLANE then return end
          if not a:inAir() then return end
          local ap = a:getPoint()
          if CIV.dist2D(ap, p) <= TW.radius and CIV.agl(ap) <= TW.maxAGL then
            watcher = info
          end
        end)
      end
      if watcher then
        chase.watcherName = watcher.playerName
        if not chase.watchAnnounced then
          chase.watchAnnounced = true
          CIV.msgAll("TRAFFIC WATCH: " .. watcher.playerName ..
            " is tracking the fugitive from above. Pressure builds " ..
            "faster while the watch holds.", 12)
        end
      end

      if contact then
        chase.pressure = math.min(100,
          chase.pressure + chase.rateUp * (watcher and TW.rateBonus or 1) * 2)   -- 2 s tick
      else
        chase.pressure = math.max(0, chase.pressure - chase.rateDown * 2)
      end

      if chase.pressure >= 100 then
        pcall(function() g:getController():setTask({ id = "Hold", params = {} }) end)
        CIV.msgAll("POLICE: fugitive STOPPED and under arrest at " .. CIV.llString(p), 20)
        local closest = nil
        CIV.forEachPlayerHelo(function(h, info)
          if CIV.dist2D(h:getPoint(), p) <= CP.pressureRadius then closest = info end
        end)
        if closest then
          CIV.Score.award(closest.playerName, "chase", 0.8, 0.5,
            CIV.severityMult(chase.severity), "fugitive arrest")
        end
        if chase.watcherName then
          CIV.Score.award(chase.watcherName, "trafficWatch", 0.8, 0.5,
            CIV.severityMult(chase.severity), "traffic watch assist")
        end
        closeChase(chase, 90)
      else
        -- extend the route when the car nears its last hop
        local last = chase.hops[#chase.hops]
        if last and CIV.dist2D(p, last.point) < 200 then
          local prev = chase.hops[#chase.hops - 1]
          chase.hops = makeHops(last, CP.routeHops, prev and prev.name or nil)
          assignRoute(chase)
        end

        -- watchdog: car stalled too long (known "On Road" bug)
        if chase.lastPos and CIV.dist2D(p, chase.lastPos) < 5 then
          chase.stalledSince = chase.stalledSince or now
          if now - chase.stalledSince > 45 then
            chase.stalledSince = nil
            chase.rekicks = chase.rekicks + 1
            if chase.rekicks >= 2 then
              chase.roadAction = "Off Road"   -- definitive fallback for this event
              CIV.dbg("Chase #" .. chase.id .. ": falling back to Off Road")
            end
            chase.hops = makeHops({ point = p, name = "current" }, CP.routeHops, nil)
            assignRoute(chase)
            CIV.dbg("Chase #" .. chase.id .. ": route re-kicked (watchdog)")
          end
        else
          chase.stalledSince = nil
        end
        chase.lastPos = { x = p.x, y = p.y, z = p.z }
      end
    end
  end
  return t + 2
end, nil, 10)

----------------------------------------------------------------------
-- SWAT
----------------------------------------------------------------------

CIV.SWAT = { _scenarios = {}, _sid = 0 }
local SW = CIV.SWAT
local swatState = {}   -- unitName -> { squad = n }

local function sState(uname)
  swatState[uname] = swatState[uname] or { squad = 0 }
  return swatState[uname]
end

-- operators required by a scenario, from its severity roll
local function requiredOperators(scen)
  return math.floor(CIV.sevLerp(scen.severity, CS.squadSize.min, CS.squadSize.max) + 0.5)
end

-- boarding sizes the team for the WORST active scenario (the squad size
-- stays fixed at boarding, per the design rule; the severity roll just
-- tells the base how many operators the callout needs)
local function boardingSize()
  local worst = nil
  for _, scen in pairs(SW._scenarios) do
    if not worst or scen.severity > worst.severity then worst = scen end
  end
  if worst then return requiredOperators(worst) end
  return math.random(CS.squadSize.min, CS.squadSize.max)
end

local function boardTeam(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local st = sState(uname)
  if st.squad > 0 then
    CIV.msgUnit(u, "Team already aboard (" .. st.squad .. " operators).", 10)
    return
  end
  if #CIV.Zones.byPrefix(C.zones.swatBase) == 0 then
    CIV.msgUnit(u, "No '" .. C.zones.swatBase .. "' zone is defined in the mission.", 10)
    return
  end
  if u:inAir() or not CIV.Zones.containing(C.zones.swatBase, u:getPoint())
     or CIV.speed(u:getVelocity()) > 1 then
    CIV.msgUnit(u, "You must be LANDED and stationary inside a SWAT base.", 10)
    return
  end
  CIV.msgUnit(u, "Boarding team: stay put for " .. CS.boardingTime .. " seconds.", 10)
  CIV.schedule(function()
    local u2 = Unit.getByName(uname)
    if not u2 or not u2:isExist() then return end
    if u2:inAir() or not CIV.Zones.containing(C.zones.swatBase, u2:getPoint())
       or CIV.speed(u2:getVelocity()) > 1 then
      CIV.msgUnit(u2, "Boarding aborted: you moved.", 10)
      return
    end
    -- squad size fixed HERE, at boarding (design rule)
    st.squad = boardingSize()
    CIV.msgUnit(u2, "SWAT team aboard: " .. st.squad ..
      " operators. Insert them on the active objective via fast-rope.", 15)
    local info = CIV.players[uname]
    if info then
      CIV.msgAll("SWAT: " .. info.playerName .. " boarded a team of " ..
        st.squad .. " operators.", 10)
    end
  end, nil, CS.boardingTime)
end

-- opts (command center): { point = vec3, severity = 1..10 }
function SW.startScenario(opts)
  local pt
  if opts and opts.point then
    SW._gmid = (SW._gmid or 0) + 1
    pt = {
      name = "GM SWAT " .. SW._gmid, radius = 60,
      point = { x = opts.point.x, y = CIV.groundY(opts.point), z = opts.point.z },
    }
  else
    pt = CIV.Pool.pick(C.zones.swatPoints, 500)
  end
  if not pt then return nil end
  SW._sid = SW._sid + 1
  -- one severity roll shapes the scenario: operators required, resolve time, score
  local scen = { id = SW._sid, pt = pt,
    severity = (opts and opts.severity)
      and math.max(1, math.min(10, opts.severity))
      or CIV.rollSeverity(CS.severity) }
  SW._scenarios[scen.id] = scen
  CIV.Pool.occupy(pt)
  scen.sceneGname = spawnPoliceScene(CS.sceneTemplates, pt.point)
  scen.circleId = CIV.drawEventZone(pt.area, "SWAT objective #" .. scen.id, "swat")

  local hp = C.hover.fastRope
  scen.watch = CIV.Hover.watch({
    center = pt.point, label = "SWAT - fast-rope",
    radius = hp.radius, minAGL = hp.minAGL, maxAGL = hp.maxAGL,
    maxSpeed = hp.maxSpeed, T = hp.T, window = hp.window, B = hp.B,
    -- only hooks helicopters carrying enough operators for this scenario
    filter = function(u) return sState(u:getName()).squad >= requiredOperators(scen) end,
    onSuccess = function(unit, session)
      local uname = unit:getName()
      local st = sState(uname)
      local squad = st.squad
      st.squad = 0
      -- the squad stays physically present and operational after insertion
      -- (unlike rescue subjects, which are despawned when picked up)
      CIV.spawnGround(pt.point, squad, C.templates.swatTeam,
        C.fallbackTypes.swat, "CIVIL_SWAT")
      CIV.msgAll("SWAT: " .. squad .. " operators inserted at " .. pt.name ..
        ". Intervention in progress.", 15)
      local info = CIV.players[uname]
      if info then
        CIV.Score.award(info.playerName, "swat",
          CIV.Score.hoverQuality(session), CIV.Score.hoverTimeFactor(session),
          CIV.severityMult(scen.severity), "SWAT insertion")
      end
      CIV.schedule(function()
        CIV.msgAll("SWAT: scenario at " .. pt.name .. " RESOLVED. Area secure.", 15)
        CIV.unmark(scen.circleId)
        CIV.Pool.release(pt)
        releaseSceneLater(scen.sceneGname)
        scen.sceneGname = nil
        SW._scenarios[scen.id] = nil
      end, nil, CS.resolveTime
        * CIV.sevLerp(scen.severity, CS.resolveFactor.atMin, CS.resolveFactor.atMax))
    end,
    onFail = function()
      CIV.msgAll("SWAT: intervention at " .. pt.name .. " FAILED (window expired).", 15)
      CIV.unmark(scen.circleId)
      CIV.Pool.release(pt)
      releaseSceneLater(scen.sceneGname)
      scen.sceneGname = nil
      SW._scenarios[scen.id] = nil
    end,
  })
  CIV.msgAll("SWAT: hostile scenario reported at " .. pt.name ..
    " (severity " .. scen.severity .. "/10, requires " ..
    requiredOperators(scen) .. "+ operators)" ..
    "\n" .. CIV.coordText(pt.point) ..
    "\nBoard a team at the base and insert it via fast-rope.", 25)
  return scen
end

-- command center: close a scenario without any outcome
function SW.cancel(scen)
  if not SW._scenarios[scen.id] then return false end
  if scen.watch then CIV.Hover.unwatch(scen.watch) end
  CIV.unmark(scen.circleId)
  CIV.Pool.release(scen.pt)
  releaseSceneLater(scen.sceneGname)
  scen.sceneGname = nil
  SW._scenarios[scen.id] = nil
  return true
end

----------------------------------------------------------------------
-- PRISONER CONVOY ESCORT
-- A police car, the school bus with the detainees and a tail car drive
-- "On Road" from a CIVIL Convoy Start zone to a CIVIL Convoy End zone,
-- with the helicopter shadowing them. Along the way an AMBUSH (CIVIL
-- Ambush template: two armed men and a car) may appear ahead of the
-- route: report it via F10 for bonus points and the police clears the
-- site; miss it and the convoy drives into it, mission FAILED with a
-- malus on the escorting pilot. The ambush clone keeps the template's
-- own country: build it under a hostile country and the gunmen shoot
-- for real, but the scripted outcome works with any country.
----------------------------------------------------------------------

CIV.Convoy = { _runs = {}, _cid = 0 }
local CVY = CIV.Convoy
local CC = CP.convoy

-- convoy group: template first, else police car + school bus + tail car
local function spawnConvoyGroup(p)
  local name = CIV.spawnFromTemplate(C.templates.convoy, p)
  if name then return name end
  local gname = CIV.uniqueName("CIVIL_CONVOY")
  local types = { C.fallbackTypes.convoyCar, C.fallbackTypes.convoyBus,
                  C.fallbackTypes.convoyCar }
  local units = {}
  for i, tp in ipairs(types) do
    units[i] = { type = tp, name = gname .. "_" .. i, unitId = CIV.newUnitId(),
      x = p.x - (i - 1) * 15, y = p.z, heading = 0, skill = "Average",
      playerCanDrive = false }
  end
  coalition.addGroup(C.countryId, Group.Category.GROUND, {
    visible = false, lateActivation = false, task = "Ground Nothing",
    name = gname, groupId = CIV.newGroupId(), units = units,
    route = { points = { { x = p.x, y = p.z, type = "Turning Point",
                           action = "Off Road", speed = 0 } } },
  })
  return gname
end

local function convoyRoute(run, fromP)
  local g = Group.getByName(run.gname)
  if not g then return end
  pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = {
      { x = fromP.x, y = fromP.z, type = "Turning Point",
        action = run.roadAction, speed = CC.speed },
      { x = run.endP.x, y = run.endP.z, type = "Turning Point",
        action = run.roadAction, speed = CC.speed },
    } } } })
  end)
end

-- opts (command center): { severity = 1..10 }
function CVY.start(opts)
  if not CC.enabled then return nil end
  local n = 0
  for _ in pairs(CVY._runs) do n = n + 1 end
  if n >= CC.maxActive then return nil end
  local starts = CIV.Zones.byPrefix(C.zones.convoyStart)
  local stops = CIV.Zones.byPrefix(C.zones.convoyEnd)
  if #starts == 0 or #stops == 0 then return nil end
  local sArea = starts[math.random(#starts)]
  local eArea = stops[math.random(#stops)]
  local sp = { x = sArea.center.x,
               y = land.getHeight({ x = sArea.center.x, y = sArea.center.z }),
               z = sArea.center.z }

  CVY._cid = CVY._cid + 1
  local run = {
    id = CVY._cid, gname = spawnConvoyGroup(sp),
    endP = { x = eArea.center.x, z = eArea.center.z }, endName = eArea.name,
    severity = (opts and opts.severity)
      and math.max(1, math.min(10, opts.severity))
      or CIV.rollSeverity(CC.severity),
    roadAction = "On Road",
    escortTicks = 0, totalTicks = 0, escortName = nil,
    lastPos = nil, stalledSince = nil, rekicks = 0,
    -- the ambush needs its template: no CIVIL Ambush group, no threat
    ambushPlanned = math.random(100) <= CC.ambush.chance
      and #CIV.Templates.byPrefix(C.templates.ambush) > 0,
    ambushAt = timer.getTime() + CIV.randBetween(CC.ambush.delay),
  }
  local okSize, size0 = pcall(function()
    return Group.getByName(run.gname):getSize()
  end)
  if okSize then run.size0 = size0 end
  CVY._runs[run.id] = run
  CIV.schedule(function() convoyRoute(run, sp) end, nil, 2)
  CIV.msgAll("CONVOY ESCORT (severity " .. run.severity .. "/10): prisoner " ..
    "transport departing " .. sArea.name .. " for " .. eArea.name ..
    ".\n" .. CIV.coordText(sp) ..
    "\nShadow the convoy. Intel says the route may be watched: report " ..
    "anything suspicious via F10 BEFORE the convoy gets there.", 25)
  CIV.log("Convoy #" .. run.id .. " severity " .. run.severity ..
    (run.ambushPlanned and " (ambush planned)" or ""))
  return run
end

local function closeRun(run, delay)
  CVY._runs[run.id] = nil
  CIV.unmark(run.markId)
  local cg = run.gname
  local ag = run.ambush and run.ambush.gname
  CIV.schedule(function()
    CIV.despawnGroup(cg)
    if ag then CIV.despawnGroup(ag) end
  end, nil, delay or 1)
end

-- command center: close a run without any outcome
function CVY.cancel(run)
  if not CVY._runs[run.id] then return false end
  closeRun(run, 1)
  return true
end

-- F10 report: valid within reportRadius of an unreported ambush
function CVY.report(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local p = u:getPoint()
  for _, run in pairs(CVY._runs) do
    local amb = run.ambush
    if amb and not amb.spotted
       and CIV.dist2D(p, amb.point) <= CC.ambush.reportRadius then
      amb.spotted = true
      local info = CIV.players[uname]
      if info then
        CIV.Score.award(info.playerName, "convoySpot", 0.9, 0.5,
          CIV.severityMult(run.severity), "convoy ambush reported")
      end
      run.markId = CIV.mark("Reported ambush (police responding)", amb.point)
      CIV.msgAll("CONVOY ESCORT: armed group reported on the route, " ..
        "marked on the F10 map. Ground units are moving in to clear the " ..
        "site before the convoy passes.", 15)
      local gname = amb.gname
      CIV.schedule(function()
        CIV.despawnGroup(gname)
        CIV.unmark(run.markId)
        run.markId = nil
        CIV.msgAll("CONVOY ESCORT: site clear. The route is safe again.", 12)
      end, nil, CC.ambush.clearDelay)
      return
    end
  end
  CIV.msgUnit(u, "Nothing suspicious in sight from here.", 10)
end

local function convoySprung(run, p)
  CIV.msgAll("CONVOY ESCORT: the convoy drove into an UNREPORTED ambush at\n" ..
    CIV.llString(p) .. "\nMission FAILED.", 20)
  pcall(trigger.action.explosion, { x = p.x, y = p.y + 2, z = p.z }, 10)
  if run.escortName then
    CIV.Score.award(run.escortName, "convoyMalus", 0.5, 0.5,
      CIV.severityMult(run.severity), "convoy lost (ambush unreported)")
  end
  closeRun(run, 20)
end

-- convoy loop: escort coverage, ambush lifecycle, arrival, watchdog
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, run in pairs(CVY._runs) do
    local g = Group.getByName(run.gname)
    local u = g and g:getUnit(1)
    if not u or not u:isExist() then
      CIV.msgAll("CONVOY ESCORT: convoy lost. Mission over.", 12)
      closeRun(run, 1)
    else
      local p = u:getPoint()

      -- escort coverage: completion quality = time on station
      run.totalTicks = run.totalTicks + 1
      local escorted = false
      CIV.forEachPlayerHelo(function(h, info)
        if not escorted and CIV.dist2D(h:getPoint(), p) <= CC.escortRadius then
          escorted = true
          run.escortName = info.playerName
        end
      end)
      if escorted then run.escortTicks = run.escortTicks + 1 end

      -- the ambush appears ahead of the convoy, just off the road
      if run.ambushPlanned and not run.ambush and now >= run.ambushAt then
        local v = u:getVelocity()
        local hdg = CIV.speed(v) > 2
          and CIV.bearingDeg(p, { x = p.x + v.x, z = p.z + v.z })
          or CIV.bearingDeg(p, { x = run.endP.x, z = run.endP.z })
        local ap = CIV.offsetPoint(p, hdg, CC.ambush.aheadM)
        ap = CIV.offsetPoint(ap, hdg + (math.random(2) == 1 and 90 or -90),
          math.random(10, CC.ambush.lateralM))
        local agname = CIV.spawnFromTemplate(C.templates.ambush, ap)
        if agname then
          run.ambush = { gname = agname, point = ap, spotted = false, hinted = {} }
          CIV.log("Convoy #" .. run.id .. ": ambush placed ahead of the route")
        else
          run.ambushPlanned = false
        end
      end

      -- hints + sprung check while the ambush is live and unreported
      local amb = run.ambush
      local sprung = false
      if amb and not amb.spotted then
        CIV.forEachPlayer(function(a, info)
          if amb.hinted[info.unitName] then return end
          local apnt = a:getPoint()
          if CIV.dist2D(apnt, amb.point) <= CC.ambush.hintRadius
             and CIV.agl(apnt) <= CC.ambush.maxAGL then
            amb.hinted[info.unitName] = true
            CIV.msgUnit(a, "Something odd off the convoy route nearby: a " ..
              "parked car and movement. Take a look and report it via F10.", 12)
          end
        end)
        local damaged = false
        local okSize, size = pcall(function() return g:getSize() end)
        if okSize and run.size0 and size < run.size0 then damaged = true end
        if damaged or CIV.dist2D(p, amb.point) <= CC.ambush.triggerRadius then
          sprung = true
          convoySprung(run, p)
        end
      end

      if not sprung then
        if CIV.dist2D(p, run.endP) <= CC.arriveRadius then
          local quality = run.escortTicks / math.max(1, run.totalTicks)
          if run.escortName then
            CIV.Score.award(run.escortName, "convoy", quality, 0.5,
              CIV.severityMult(run.severity),
              string.format("convoy escort (coverage %d%%)",
                math.floor(quality * 100)))
          end
          CIV.msgAll("CONVOY ESCORT: the transport reached " .. run.endName ..
            ". Detainees delivered." ..
            (run.escortName and "" or " No escort was on station."), 15)
          closeRun(run, 60)
        else
          -- stall watchdog (same "On Road" caveat as the chase)
          if run.lastPos and CIV.dist2D(p, run.lastPos) < 5 then
            run.stalledSince = run.stalledSince or now
            if now - run.stalledSince > 60 then
              run.stalledSince = nil
              run.rekicks = run.rekicks + 1
              if run.rekicks >= 2 then run.roadAction = "Off Road" end
              convoyRoute(run, p)
              CIV.dbg("Convoy #" .. run.id .. " re-kicked (watchdog)")
            end
          else
            run.stalledSince = nil
          end
          run.lastPos = { x = p.x, y = p.y, z = p.z }
        end
      end
    end
  end
  return t + 5
end, nil, 20)

----------------------------------------------------------------------
-- F10 MENU + EVENT STARTERS
----------------------------------------------------------------------

CIV.Menu_register(function(gid, uname)
  local sub = missionCommands.addSubMenuForGroup(gid, "Police / SWAT", CIV.rootMenu[gid])
  missionCommands.addCommandForGroup(gid, "Board SWAT team (at base)", sub, boardTeam, uname)
  missionCommands.addCommandForGroup(gid, "Team status", sub, function()
    local st = sState(uname)
    CIV.msgGroupId(gid, st.squad > 0
      and ("Team aboard: " .. st.squad .. " operators.")
      or "No team aboard.", 10)
  end)
  missionCommands.addCommandForGroup(gid, "Convoy: report suspicious activity",
    sub, CVY.report, uname)
end)

CIV.EventStarters.chase = { label = "Police chase", fn = PL.startChase }
CIV.EventStarters.swat = { label = "SWAT scenario", fn = SW.startScenario }
CIV.EventStarters.convoy = { label = "Prisoner convoy escort",
  fn = function() return CVY.start() end }

CIV.log("CivilPolice loaded")

-- ====================================================================
-- >>> Scripts/40_CivilTransport.lua
-- ====================================================================
----------------------------------------------------------------------
-- DCS Civil Mission Template - Civil Cargo Transport (mass tiers)
-- File: 40_CivilTransport.lua  (requires 01_CivilCore.lua)
--
--   - Fixed mass tiers LIGHT/MEDIUM/HEAVY + HEAVY_LIFT: objective masses
--     (kg in config), never rescaled to whoever lifts them.
--   - Heavy-lift gate: the HEAVY_LIFT tier is generated only if a type
--     with capacity >= threshold is present in the mission (tracked via
--     S_EVENT_BIRTH in CIV.typesPresent: covers MP slot changes).
--   - Arrival WARNING (not a block) if the player's type is not suited to
--     the tier, from the same type->capacity table used by the gate.
--   - Tier change via F10 with a delay (despawn + respawn: cargo mass is
--     not editable at runtime, verified).
--   - Native mass: mass/canCargo fields of coalition.addStaticObject.
--     WARNING: some cargo types have a fixed mass -> validate the
--     configured types in the Mission Editor.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config
local CC = C.cargo

CIV.Cargo = { _points = {}, _pid = 0 }
local CG = CIV.Cargo

----------------------------------------------------------------------
-- HEAVY-LIFT GATE + TIER SELECTION
----------------------------------------------------------------------

local function heavyLiftPresent()
  for typeName in pairs(CIV.typesPresent) do
    local cap = C.capacity[typeName]
    if cap and cap >= CC.heavyLiftMinKg then return true end
  end
  return false
end

local function randomTier()
  if heavyLiftPresent() and math.random(100) <= 15 then return "HEAVY_LIFT" end
  local total = 0
  for _, w in pairs(CC.tierWeights) do total = total + w end
  local r, acc = math.random(total), 0
  for tier, w in pairs(CC.tierWeights) do
    acc = acc + w
    if r <= acc then return tier end
  end
  return "MEDIUM"
end

----------------------------------------------------------------------
-- ACTIVE LOADING POINTS
----------------------------------------------------------------------

-- opts (command center): { point = vec3, priority = 1..10 }
function CG.startPoint(forcedTier, opts)
  local n = 0
  for _ in pairs(CG._points) do n = n + 1 end
  if not (opts and opts.point) and n >= CC.maxActive then return nil end

  local pt
  if opts and opts.point then
    CG._gmid = (CG._gmid or 0) + 1
    pt = {
      name = "GM cargo " .. CG._gmid, radius = 100,
      point = { x = opts.point.x, y = CIV.groundY(opts.point), z = opts.point.z },
    }
  else
    pt = CIV.Pool.pick(C.zones.cargoPoints, 800)
  end
  if not pt then return nil end

  local tier = forcedTier or randomTier()
  CG._pid = CG._pid + 1
  -- delivery priority (transport flavor of the severity scale): one roll
  -- per point, drives the score multiplier and the time to live
  local priority = (opts and opts.priority)
    and math.max(1, math.min(10, opts.priority))
    or CIV.rollSeverity(CC.priority)
  local point = {
    id = CG._pid, pt = pt, tier = tier,
    priority = priority,
    expiresAt = timer.getTime()
      + CIV.sevLerp(priority, CC.priorityTtl.atMin, CC.priorityTtl.atMax),
    cargoName = CIV.spawnCargo(pt.point, CC.tiers[tier].cargoType,
      CC.tiers[tier].kg, "CIVIL_TRANSPORT"),
    spawnPos = { x = pt.point.x, y = pt.point.y, z = pt.point.z },
    warned = {}, changing = false,
  }
  CG._points[point.id] = point
  CIV.Pool.occupy(pt)
  point.zoneMarkId = CIV.drawEventZone(pt.area,
    "Cargo pickup " .. pt.name .. " (" .. tier .. ", priority " .. priority .. ")",
    "transport")
  CIV.msgAll(string.format(
    "TRANSPORT: %s load (%d kg, priority %d/10) available at %s\n%s\n" ..
    "Destination: %s (pickup zone highlighted on the F10 map). " ..
    "Expires in %d minutes.",
    tier, CC.tiers[tier].kg, priority, pt.name, CIV.coordText(pt.point),
    C.zones.cargoDestination,
    math.floor((point.expiresAt - timer.getTime()) / 60)), 25)
  return point
end

local function closePoint(point)
  CIV.unmark(point.zoneMarkId)
  CIV.Pool.release(point.pt)
  CG._points[point.id] = nil
end

-- command center: close a loading point without any outcome
function CG.cancel(point)
  if not CG._points[point.id] then return false end
  if point.cargoName then CIV.despawnStatic(point.cargoName) end
  closePoint(point)
  return true
end

----------------------------------------------------------------------
-- ARRIVAL WARNING (advice, not a block)
----------------------------------------------------------------------

CIV.schedule(function(_, t)
  for _, point in pairs(CG._points) do
    CIV.forEachPlayerHelo(function(u, info)
      if point.warned[info.unitName] then return end
      if CIV.dist2D(u:getPoint(), point.pt.point) <= CC.warnRadius then
        point.warned[info.unitName] = true
        local cap = C.capacity[info.typeName]
        local kg = CC.tiers[point.tier].kg
        if cap and cap < kg then
          CIV.msgUnit(u, string.format(
            "WARNING: the load at %s is %s (%d kg), above the estimated " ..
            "capacity of your %s (%d kg). It requires a heavier aircraft, " ..
            "or change the tier via F10 (cost: %ds).",
            point.pt.name, point.tier, kg, info.typeName, cap, CC.tierChangeDelay), 20)
        elseif not cap then
          CIV.msgUnit(u, "Type " .. info.typeName ..
            " missing from the capacity table: update CIV.Config.capacity.", 15)
        end
      end
    end)
  end
  return t + 5
end, nil, 15)

----------------------------------------------------------------------
-- TIER CHANGE VIA F10 (free in both directions, with a real cost)
----------------------------------------------------------------------

local function nearbyPoint(u)
  local p = u:getPoint()
  for _, point in pairs(CG._points) do
    if CIV.dist2D(p, point.pt.point) <= CC.warnRadius then return point end
  end
  return nil
end

local function changeTier(args)
  local uname, tier = args[1], args[2]
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local point = nearbyPoint(u)
  if not point then
    CIV.msgUnit(u, "No loading point nearby.", 10)
    return
  end
  if point.changing then
    CIV.msgUnit(u, "Re-rigging already in progress at this point.", 10)
    return
  end
  if point.tier == tier then
    CIV.msgUnit(u, "The load is already " .. tier .. ".", 10)
    return
  end
  if tier == "HEAVY_LIFT" and not heavyLiftPresent() then
    CIV.msgUnit(u, "HEAVY_LIFT tier unavailable: no heavy-lift aircraft in the mission.", 10)
    return
  end
  point.changing = true
  CIV.despawnStatic(point.cargoName)
  CIV.msgUnit(u, "Re-rigging the load to " .. tier .. ": ready in " ..
    CC.tierChangeDelay .. " seconds.", 12)
  CIV.schedule(function()
    if not CG._points[point.id] then return end   -- point closed meanwhile
    point.tier = tier
    point.cargoName = CIV.spawnCargo(point.pt.point, CC.tiers[tier].cargoType,
      CC.tiers[tier].kg, "CIVIL_TRANSPORT")
    point.changing = false
    point.warned = {}
    CIV.msgAll("TRANSPORT: load at " .. point.pt.name .. " re-rigged to " ..
      tier .. " (" .. CC.tiers[tier].kg .. " kg).", 12)
  end, nil, CC.tierChangeDelay)
end

----------------------------------------------------------------------
-- DELIVERY
-- The (slung) cargo arrives inside the destination zone. Detected by
-- polling the cargo position; slung-object behavior TO TEST in-game.
----------------------------------------------------------------------

CIV.schedule(function(_, t)
  if #CIV.Zones.byPrefix(C.zones.cargoDestination) == 0 then return t + 60 end
  for id, point in pairs(CG._points) do
    -- urgent loads expire if nobody delivers them in time
    if timer.getTime() > point.expiresAt then
      CIV.msgAll("TRANSPORT: load at " .. point.pt.name ..
        " EXPIRED undelivered (priority " .. point.priority .. "/10).", 12)
      if point.cargoName then CIV.despawnStatic(point.cargoName) end
      closePoint(point)
    elseif point.cargoName and not point.changing then
      local s = StaticObject.getByName(point.cargoName)
      if not s then
        -- cargo destroyed (dropped/broken): event closed without points
        CIV.msgAll("TRANSPORT: load at " .. point.pt.name .. " LOST.", 12)
        closePoint(point)
      else
        local p = s:getPoint()
        if CIV.Zones.containing(C.zones.cargoDestination, p) and CIV.agl(p) < 5
           and CIV.dist2D(p, point.spawnPos) > 500 then
          -- delivered: credit the closest player helicopter
          local closest, minDist = nil, 1e9
          CIV.forEachPlayerHelo(function(u, info)
            local d = CIV.dist2D(u:getPoint(), p)
            if d < minDist then minDist, closest = d, info end
          end)
          CIV.msgAll("TRANSPORT: " .. point.tier .. " load delivered to " ..
            C.zones.cargoDestination .. "!", 15)
          if closest and minDist < 500 then
            CIV.Score.award(closest.playerName, "transport", 0.8, 0.5,
              C.score.tierMult[point.tier] * CIV.severityMult(point.priority),
              point.tier .. " transport (priority " .. point.priority .. ")")
          end
          CIV.despawnStatic(point.cargoName)
          closePoint(point)
        end
      end
    end
  end
  return t + 3
end, nil, 20)

----------------------------------------------------------------------
-- SUPPLY AIRDROP (official C-130 module, crate type containers)
-- Differentiated crates: retardant drops use drum/barrel crates on fires
-- (see 10_CivilFirefighting), supply drops use crates landing INSIDE the
-- cargo destination zone. Same dual-channel detection via CIV.Airdrop
-- (channel 1) plus a destination-zone object scan (channel 2). Crate
-- types and triggering channel TO VALIDATE against the official module.
----------------------------------------------------------------------

CG.airdropped = 0   -- delivered supply containers (session counter)

if CC.airdrop.enabled then
  local matchesType = CIV.Airdrop.typeMatcher(CC.airdrop.containerTypes)

  local function supplyDelivered(impact)
    if not CIV.Zones.containing(C.zones.cargoDestination, impact) then return false end
    CG.airdropped = CG.airdropped + 1
    local playerInfo = CIV.nearestPlayerAirplane(impact, CC.airdrop.creditRadius)
    if playerInfo then
      CIV.Score.award(playerInfo.playerName, "transport", 0.7, 0.5,
        CC.airdrop.scoreMult, "supply airdrop")
    else
      CIV.msgAll("TRANSPORT: supply container delivered by airdrop to " ..
        C.zones.cargoDestination .. ".", 12)
    end
    return true
  end

  CIV.Airdrop.register({
    key = "supply", matchesType = matchesType,
    matchAny = CC.airdrop.matchAnyObject,
    onImpact = function(point) return supplyDelivered(point) end,
  })

  -- Channel 2: foreign objects appearing inside the destination zone
  local processedObjects = {}
  CIV.schedule(function(_, t)
    if not (world.searchObjects and world.VolumeType and Object and Object.Category) then
      return t + 60
    end
    local dests = CIV.Zones.byPrefix(C.zones.cargoDestination)
    if #dests == 0 then return t + 60 end
    for _, dest in ipairs(dests) do
      local center = { x = dest.center.x,
                       y = land.getHeight({ x = dest.center.x, y = dest.center.z }),
                       z = dest.center.z }
      local volume = { id = world.VolumeType.SPHERE,
                       params = { point = center, radius = dest.radius } }
      pcall(world.searchObjects, Object.Category.STATIC, volume, function(obj)
        local ok, name = pcall(function() return obj:getName() end)
        if ok and name and not processedObjects[name]
           and string.sub(tostring(name), 1, 6) ~= "CIVIL_" then
          processedObjects[name] = true
          local okT, typeName = pcall(function() return obj:getTypeName() end)
          if CC.airdrop.matchAnyObject or (okT and typeName and matchesType(typeName)) then
            CIV.dbg("Foreign cargo object in destination zone: " .. tostring(name))
            local ok2, p = pcall(function() return obj:getPoint() end)
            if ok2 and p then supplyDelivered(p) end
          end
        end
        return true
      end)
    end
    return t + 5
  end, nil, 12)
end

----------------------------------------------------------------------
-- F10 MENU + EVENT STARTER
----------------------------------------------------------------------

CIV.Menu_register(function(gid, uname)
  local sub = missionCommands.addSubMenuForGroup(gid, "Cargo transport", CIV.rootMenu[gid])
  local changeSub = missionCommands.addSubMenuForGroup(gid, "Change tier of nearby point", sub)
  for _, tier in ipairs({ "LIGHT", "MEDIUM", "HEAVY", "HEAVY_LIFT" }) do
    missionCommands.addCommandForGroup(gid,
      tier .. " (" .. CC.tiers[tier].kg .. " kg)", changeSub, changeTier, { uname, tier })
  end
  missionCommands.addCommandForGroup(gid, "Active loading points", sub, function()
    local n, txt = 0, "Active loading points:\n"
    for _, point in pairs(CG._points) do
      n = n + 1
      txt = txt .. string.format("- %s: %s (%d kg, priority %d/10, %d min left)  %s\n",
        point.pt.name, point.tier, CC.tiers[point.tier].kg, point.priority,
        math.max(0, math.floor((point.expiresAt - timer.getTime()) / 60)),
        CIV.llString(point.pt.point))
    end
    CIV.msgGroupId(gid, n > 0 and txt or "No active loading points.", 20)
  end)
end)

CIV.EventStarters.transport = { label = "Transport point", fn = CG.startPoint }

CIV.log("CivilTransport loaded")

-- ====================================================================
-- >>> Scripts/45_CivilAviation.lua
-- ====================================================================
----------------------------------------------------------------------
-- DCS Civil Mission Template - Aviation tasks
-- File: 45_CivilAviation.lua  (requires 01_CivilCore.lua; load after the
-- other intervention files, before 50_CivilCommand.lua)
--
--   RECON: an anomaly appears on one of the "CIVIL Recon Point" corridor
--   waypoints (power line, pipeline...). Fly the corridor low: within
--   hintRadius you get a nudge, overhead and below maxAGL you report it
--   via F10. Optional visual from the "CIVIL Anomaly" template.
--
--   VIP SHUTTLE: a passenger waits at one "CIVIL VIP Pad" for a ride to
--   another. Board and drop off by holding landed on the pad. Ride
--   comfort IS the score quality: acceleration spikes eat it away.
--   Helicopters AND airplanes: put pads on airfield aprons and the light
--   trainers (Yak-52, MB-339, L-39, C-101...) get an air-taxi job.
--
--   MEDIA: any player helicopter or airplane holding in the filming ring
--   around an active event accumulates footage; when the story airs the
--   pilot is credited. One award per event, passive, no menu needed.
--
--   MEDICAL TRANSFER: event chain on the rescue module. A delivered
--   high-severity patient sometimes needs a second leg to a regional
--   hospital far away: pad to pad on the VIP Pad pool, with a criticality
--   clock and a tighter comfort threshold. The air ambulance job.
--
--   SKYDIVE: climb over a "CIVIL Drop Zone", release the jumpers via F10.
--   Landing point = wind drift (freefall damped + full canopy) plus a
--   steer correction toward the center; score quality = accuracy.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config

----------------------------------------------------------------------
-- INFRASTRUCTURE RECON
----------------------------------------------------------------------

CIV.Recon = { _anomalies = {}, _aid = 0 }
local RC = CIV.Recon
local CR = C.recon

-- opts (command center): { point = vec3, severity = 1..10 }
function RC.start(opts)
  local n = 0
  for _ in pairs(RC._anomalies) do n = n + 1 end
  if not (opts and opts.point) and n >= CR.maxActive then return nil end

  local pt
  if opts and opts.point then
    RC._aid = RC._aid + 1
    pt = { name = "GM anomaly " .. RC._aid, radius = 100,
           point = { x = opts.point.x, y = CIV.groundY(opts.point), z = opts.point.z } }
  else
    pt = CIV.Pool.pick(C.zones.reconPoints, 500)
  end
  if not pt then return nil end

  RC._aid = RC._aid + 1
  local sev = (opts and opts.severity)
    and math.max(1, math.min(10, opts.severity))
    or CIV.rollSeverity(CR.severity)
  local anomaly = {
    id = RC._aid, pt = pt, point = pt.point, severity = sev,
    scoreBonus = (opts and opts.scoreBonus) or 1,   -- task-board priority bonus
    expiresAt = timer.getTime() + CR.ttl,
    startedAt = timer.getTime(),
    hinted = {},
    gname = CIV.spawnFromTemplate(C.templates.anomaly, pt.point),
  }
  if CR.smokeVisual then
    -- thin smoke column: the fault is findable by eye, not only by the
    -- hint message (effectSmokeBig preset 5 = small smoke, no fire)
    anomaly.smokeName = "CIVIL_ANOMALY_" .. anomaly.id
    trigger.action.effectSmokeBig(anomaly.point, 5, 0.4, anomaly.smokeName)
  end
  RC._anomalies[anomaly.id] = anomaly
  CIV.Pool.occupy(pt)
  CIV.msgAll("INFRASTRUCTURE PATROL (severity " .. sev .. "/10): an anomaly " ..
    "is reported along the inspection corridor. Fly the recon line below " ..
    CR.maxAGL .. " m AGL and report it via F10 when overhead. " ..
    "Expires in " .. math.floor(CR.ttl / 60) .. " minutes.", 25)
  CIV.log("Recon anomaly #" .. anomaly.id .. " at " .. pt.name ..
    " severity " .. sev)
  return anomaly
end

local function closeAnomaly(anomaly)
  RC._anomalies[anomaly.id] = nil
  CIV.Pool.release(anomaly.pt)
  if anomaly.smokeName then trigger.action.effectSmokeStop(anomaly.smokeName) end
  if anomaly.gname then CIV.despawnGroup(anomaly.gname) end
end

-- command center: close an anomaly without any outcome
function RC.cancel(anomaly)
  if not RC._anomalies[anomaly.id] then return false end
  closeAnomaly(anomaly)
  return true
end

-- F10 report: valid when overhead (reportRadius) and low (maxAGL)
local function reportAnomaly(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local p = u:getPoint()
  if CIV.agl(p) > CR.maxAGL then
    CIV.msgUnit(u, "Too high for a positive identification: get below " ..
      CR.maxAGL .. " m AGL.", 10)
    return
  end
  for _, anomaly in pairs(RC._anomalies) do
    if CIV.dist2D(p, anomaly.point) <= CR.reportRadius then
      local info = CIV.players[uname]
      if info then
        local timeFactor = math.max(0,
          1 - (timer.getTime() - anomaly.startedAt) / CR.ttl)
        CIV.Score.award(info.playerName, "recon", 0.8, timeFactor,
          CIV.severityMult(anomaly.severity) * (anomaly.scoreBonus or 1),
          "anomaly reported")
      end
      CIV.msgAll("RECON: anomaly at " .. anomaly.pt.name ..
        " identified and reported. Maintenance is on the way.", 15)
      closeAnomaly(anomaly)
      return
    end
  end
  CIV.msgUnit(u, "Nothing to report here.", 10)
end

-- expiry + proximity hints
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, anomaly in pairs(RC._anomalies) do
    if now > anomaly.expiresAt then
      CIV.msgAll("RECON: the corridor anomaly went unreported and caused " ..
        "an outage. Task failed.", 15)
      closeAnomaly(anomaly)
    else
      CIV.forEachPlayer(function(u, info)
        if anomaly.hinted[info.unitName] then return end
        local p = u:getPoint()
        if CIV.dist2D(p, anomaly.point) <= CR.hintRadius
           and CIV.agl(p) <= CR.maxAGL then
          anomaly.hinted[info.unitName] = true
          CIV.msgUnit(u, "Something looks off along the line nearby: get " ..
            "overhead and report it via F10.", 12)
        end
      end)
    end
  end
  return t + 5
end, nil, 15)

----------------------------------------------------------------------
-- VIP SHUTTLE
----------------------------------------------------------------------

CIV.VIP = { _jobs = {}, _vid = 0 }
local VP = CIV.VIP
local CV = C.vip

local function padCandidates()
  return CIV.Pool.load(C.zones.vipPads)
end

-- opts (command center): { point = vec3 (pickup snaps to nearest pad),
--                          severity = 1..10 }
function VP.start(opts)
  local n = 0
  for _ in pairs(VP._jobs) do n = n + 1 end
  if not (opts and opts.point) and n >= CV.maxActive then return nil end

  local pads = padCandidates()
  if #pads < 2 then return nil end

  local from
  if opts and opts.point then
    local bestDist = 1e12
    for _, pad in ipairs(pads) do
      local d = CIV.dist2D(pad.point, opts.point)
      if d < bestDist then from, bestDist = pad, d end
    end
  else
    from = pads[math.random(#pads)]
  end
  local dest
  for _ = 1, 20 do
    local candidate = pads[math.random(#pads)]
    if candidate.name ~= from.name then dest = candidate break end
  end
  if not dest then return nil end

  VP._vid = VP._vid + 1
  local job = {
    id = VP._vid, from = from, to = dest,
    severity = (opts and opts.severity)
      and math.max(1, math.min(10, opts.severity))
      or CIV.rollSeverity(CV.severity),
    scoreBonus = (opts and opts.scoreBonus) or 1,   -- task-board priority bonus
    expiresAt = timer.getTime() + CV.pickupTtl,
    state = "waiting", unitName = nil,
    penalty = 0, lastVel = nil, lastComplaint = 0,
    boardTimer = {}, dropTimer = nil,
    gname = CIV.spawnFromTemplate(C.templates.vip, from.point),
  }
  VP._jobs[job.id] = job
  CIV.msgAll("VIP SHUTTLE (severity " .. job.severity .. "/10): passenger " ..
    "waiting at " .. from.name .. " for transport to " .. dest.name ..
    ".\n" .. CIV.coordText(from.point) ..
    "\nLand on the pad and hold for " .. CV.boardSeconds ..
    " seconds. Smooth flying pays: the passenger scores the ride.", 25)
  return job
end

local function closeJob(job)
  VP._jobs[job.id] = nil
  if job.gname then CIV.despawnGroup(job.gname) end
end

-- command center: close a job without any outcome
function VP.cancel(job)
  if not VP._jobs[job.id] then return false end
  closeJob(job)
  return true
end

local function landedOnPad(u, pad)
  return (not u:inAir())
    and CIV.speed(u:getVelocity()) <= 2.0
    and CIV.dist2D(u:getPoint(), pad.point) <= CV.padRadius
end

CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, job in pairs(VP._jobs) do
    if job.state == "waiting" then
      if now > job.expiresAt then
        CIV.msgAll("VIP SHUTTLE: the passenger at " .. job.from.name ..
          " gave up waiting. Task expired.", 12)
        closeJob(job)
      else
        -- helicopters and airplanes: place VIP pads on airfield aprons to
        -- give the light trainers an air-taxi job
        CIV.forEachPlayer(function(u, info)
          if info.category ~= Unit.Category.HELICOPTER
             and info.category ~= Unit.Category.AIRPLANE then return end
          if job.state ~= "waiting" then return end
          if landedOnPad(u, job.from) then
            job.boardTimer[info.unitName] = (job.boardTimer[info.unitName] or 0) + 2
            if job.boardTimer[info.unitName] >= CV.boardSeconds then
              job.state = "flying"
              job.unitName = info.unitName
              job.lastVel = u:getVelocity()
              if job.gname then CIV.despawnGroup(job.gname) job.gname = nil end
              CIV.msgUnit(u, "Passenger aboard. Destination: " .. job.to.name ..
                "\n" .. CIV.coordText(job.to.point) ..
                "\nKeep it smooth: hard maneuvers cost you the tip.", 20)
              CIV.msgAll("VIP SHUTTLE: " .. info.playerName ..
                " picked up the passenger at " .. job.from.name ..
                ", bound for " .. job.to.name .. ".", 10)
            end
          else
            job.boardTimer[info.unitName] = nil
          end
        end)
      end
    elseif job.state == "flying" then
      local u = Unit.getByName(job.unitName)
      if not u or not u:isExist() then
        CIV.msgAll("VIP SHUTTLE: transport lost with the passenger aboard.", 12)
        closeJob(job)
      else
        -- comfort sampling: acceleration spike = penalty (2 s tick)
        local v = u:getVelocity()
        if job.lastVel then
          local ax = (v.x - job.lastVel.x) / 2
          local ay = (v.y - job.lastVel.y) / 2
          local az = (v.z - job.lastVel.z) / 2
          local accel = math.sqrt(ax * ax + ay * ay + az * az)
          if accel > CV.comfort.accelLimit then
            job.penalty = job.penalty + CV.comfort.penaltyPerHit
            if now - job.lastComplaint > 30 then
              job.lastComplaint = now
              CIV.msgUnit(u, "The passenger grips the seat. Smoother, please.", 8)
            end
          end
        end
        job.lastVel = v
        -- dropoff
        if landedOnPad(u, job.to) then
          job.dropTimer = (job.dropTimer or 0) + 2
          if job.dropTimer >= CV.boardSeconds then
            local info = CIV.players[job.unitName]
            local quality = math.max(0, 1 - job.penalty)
            if info then
              CIV.Score.award(info.playerName, "vip", quality, 0.5,
                CIV.severityMult(job.severity) * (job.scoreBonus or 1),
                string.format("VIP shuttle (comfort %d%%)", math.floor(quality * 100)))
            end
            CIV.msgAll("VIP SHUTTLE: passenger delivered to " .. job.to.name ..
              " (ride comfort " .. math.floor(quality * 100) .. "%).", 15)
            closeJob(job)
          end
        else
          job.dropTimer = nil
        end
      end
    end
  end
  return t + 2
end, nil, 15)

----------------------------------------------------------------------
-- MEDICAL TRANSFER (air ambulance)
-- Chain trigger: the rescue module's hospital delivery loop calls
-- MT.maybeStart (guarded) after a successful delivery. Standalone starts
-- work too (admin menu, "civil transfer" marker command).
----------------------------------------------------------------------

CIV.MedTransfer = { _jobs = {}, _tid = 0 }
local MT = CIV.MedTransfer
local CT = C.medTransfer

-- opts: { severity = 1..10, nearPoint = vec3 (pickup snaps to nearest pad) }
function MT.start(opts)
  if not CT.enabled then return nil end
  local pads = padCandidates()
  if #pads < 2 then return nil end
  opts = opts or {}

  local from
  if opts.nearPoint then
    local bestDist = 1e12
    for _, pad in ipairs(pads) do
      local d = CIV.dist2D(pad.point, opts.nearPoint)
      if d < bestDist then from, bestDist = pad, d end
    end
  else
    from = pads[math.random(#pads)]
  end

  -- the regional hospital should be a real leg away; when the pool is
  -- tight, fall back to the farthest pad available
  local candidates, farthest, farDist = {}, nil, -1
  for _, pad in ipairs(pads) do
    if pad.name ~= from.name then
      local d = CIV.dist2D(pad.point, from.point)
      if d >= CT.minLeg then candidates[#candidates + 1] = pad end
      if d > farDist then farthest, farDist = pad, d end
    end
  end
  local dest = #candidates > 0 and candidates[math.random(#candidates)] or farthest
  if not dest then return nil end

  MT._tid = MT._tid + 1
  local sev = opts.severity
    and math.max(1, math.min(10, opts.severity))
    or CIV.rollSeverity({ min = CT.minSeverity, max = 10 })
  local job = {
    id = MT._tid, from = from, to = dest, severity = sev,
    scoreBonus = opts.scoreBonus or 1,   -- task-board priority bonus
    deadline = timer.getTime()
      + CIV.sevLerp(sev, CT.deadline.atMin, CT.deadline.atMax),
    deadlineTotal = CIV.sevLerp(sev, CT.deadline.atMin, CT.deadline.atMax),
    expiresAt = timer.getTime() + CT.pickupTtl,
    state = "waiting", unitName = nil,
    penalty = 0, lastVel = nil, lastComplaint = 0,
    boardTimer = {}, dropTimer = nil,
    gname = CIV.spawnFromTemplate(C.templates.survivor, from.point),
  }
  MT._jobs[job.id] = job
  CIV.msgAll("MEDICAL TRANSFER (severity " .. sev .. "/10): a patient at " ..
    from.name .. " must reach the regional hospital at " .. dest.name ..
    ".\n" .. CIV.coordText(from.point) ..
    "\nCriticality: " .. math.floor(job.deadlineTotal / 60) .. " minutes. " ..
    "Land and hold " .. CT.boardSeconds .. " seconds to board. Fly fast " ..
    "AND smooth: this passenger is on a stretcher.", 25)
  CIV.log("Medical transfer #" .. job.id .. " " .. from.name .. " -> " ..
    dest.name .. " severity " .. sev)
  return job
end

-- rescue chain hook, called (guarded) by the hospital delivery loop
function MT.maybeStart(severity, deliveryPoint)
  if not CT.enabled then return end
  if (severity or 0) < CT.minSeverity then return end
  if math.random(100) > CT.chance then return end
  MT.start({ severity = severity, nearPoint = deliveryPoint })
end

local function closeTransfer(job)
  MT._jobs[job.id] = nil
  if job.gname then CIV.despawnGroup(job.gname) end
end

-- command center: close a job without any outcome
function MT.cancel(job)
  if not MT._jobs[job.id] then return false end
  closeTransfer(job)
  return true
end

CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, job in pairs(MT._jobs) do
    if now > job.deadline then
      CIV.msgAll("MEDICAL TRANSFER: the patient did not survive the wait. " ..
        "Task failed.", 15)
      closeTransfer(job)
    elseif job.state == "waiting" then
      if now > job.expiresAt then
        CIV.msgAll("MEDICAL TRANSFER: reassigned to a ground ambulance. " ..
          "Task expired.", 12)
        closeTransfer(job)
      else
        -- pads sit on aprons: airplanes are the natural air ambulance,
        -- but a helicopter may take the leg too
        CIV.forEachPlayer(function(u, info)
          if info.category ~= Unit.Category.HELICOPTER
             and info.category ~= Unit.Category.AIRPLANE then return end
          if job.state ~= "waiting" then return end
          if landedOnPad(u, job.from) then
            job.boardTimer[info.unitName] = (job.boardTimer[info.unitName] or 0) + 2
            if job.boardTimer[info.unitName] >= CT.boardSeconds then
              job.state = "flying"
              job.unitName = info.unitName
              job.lastVel = u:getVelocity()
              if job.gname then CIV.despawnGroup(job.gname) job.gname = nil end
              CIV.msgUnit(u, "Patient aboard. Destination: " .. job.to.name ..
                "\n" .. CIV.coordText(job.to.point) ..
                "\nCriticality: " .. math.max(0,
                  math.floor((job.deadline - now) / 60)) .. " minutes.", 20)
              CIV.msgAll("MEDICAL TRANSFER: " .. info.playerName ..
                " has the patient aboard, bound for " .. job.to.name .. ".", 10)
            end
          else
            job.boardTimer[info.unitName] = nil
          end
        end)
      end
    elseif job.state == "flying" then
      local u = Unit.getByName(job.unitName)
      if not u or not u:isExist() then
        CIV.msgAll("MEDICAL TRANSFER: transport lost with the patient aboard.", 12)
        closeTransfer(job)
      else
        -- comfort sampling like the VIP job, tighter threshold (2 s tick)
        local v = u:getVelocity()
        if job.lastVel then
          local ax = (v.x - job.lastVel.x) / 2
          local ay = (v.y - job.lastVel.y) / 2
          local az = (v.z - job.lastVel.z) / 2
          local accel = math.sqrt(ax * ax + ay * ay + az * az)
          if accel > CT.comfort.accelLimit then
            job.penalty = job.penalty + CT.comfort.penaltyPerHit
            if now - job.lastComplaint > 30 then
              job.lastComplaint = now
              CIV.msgUnit(u, "The medic in the back: keep it steady!", 8)
            end
          end
        end
        job.lastVel = v
        if landedOnPad(u, job.to) then
          job.dropTimer = (job.dropTimer or 0) + 2
          if job.dropTimer >= CT.boardSeconds then
            local info = CIV.players[job.unitName]
            local quality = math.max(0, 1 - job.penalty)
            local timeFactor = math.max(0, (job.deadline - now) / job.deadlineTotal)
            if info then
              CIV.Score.award(info.playerName, "medTransfer", quality, timeFactor,
                CIV.severityMult(job.severity) * (job.scoreBonus or 1),
                string.format("medical transfer (comfort %d%%)",
                  math.floor(quality * 100)))
            end
            CIV.msgAll("MEDICAL TRANSFER: patient handed over at " ..
              job.to.name .. " in time.", 15)
            closeTransfer(job)
          end
        else
          job.dropTimer = nil
        end
      end
    end
  end
  return t + 2
end, nil, 15)

----------------------------------------------------------------------
-- SKYDIVE DROPS (the flying club)
----------------------------------------------------------------------

CIV.Skydive = {}
local SK = CIV.Skydive
local SKC = C.skydive
local lastDrop = {}   -- unitName -> time of the last release

function SK.release(uname)
  if not SKC.enabled then return end
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local info = CIV.players[uname]
  if not info then return end
  if not u:inAir() then
    CIV.msgUnit(u, "The jumpers politely decline to exit on the ground.", 10)
    return
  end
  local p = u:getPoint()
  local dz = CIV.Zones.containing(C.zones.dropZones, p)
  if not dz then
    CIV.msgUnit(u, #CIV.Zones.byPrefix(C.zones.dropZones) == 0
      and ("No '" .. C.zones.dropZones .. "' zone is defined in this mission.")
      or "You are not over a drop zone.", 10)
    return
  end
  local agl = CIV.agl(p)
  if agl < SKC.minAGL then
    CIV.msgUnit(u, "Too low for a jump: release above " .. SKC.minAGL ..
      " m AGL.", 10)
    return
  end
  local now = timer.getTime()
  if lastDrop[uname] and now - lastDrop[uname] < SKC.cooldown then
    CIV.msgUnit(u, "The next load of jumpers is still kitting up: " ..
      math.ceil(SKC.cooldown - (now - lastDrop[uname])) .. " s.", 10)
    return
  end
  lastDrop[uname] = now

  -- wind sampled once at mid-canopy height (zero wind if the API balks)
  local wind = { x = 0, y = 0, z = 0 }
  pcall(function()
    local w = atmosphere.getWind({ x = p.x,
      y = CIV.groundY(p) + SKC.openAGL / 2, z = p.z })
    if w and w.x then wind = w end
  end)
  local ffTime = math.max(0, agl - SKC.openAGL) / SKC.freefallSpeed
  local canopyTime = math.min(agl, SKC.openAGL) / SKC.canopySink
  local drift = ffTime * SKC.freefallDrift + canopyTime
  local lp = { x = p.x + wind.x * drift, z = p.z + wind.z * drift }

  -- under canopy the jumpers steer back toward the DZ center
  local center = { x = dz.center.x, z = dz.center.z }
  local off = CIV.dist2D(lp, center)
  if off > 0 then
    local pull = math.min(SKC.steerM, off)
    lp.x = lp.x + (center.x - lp.x) / off * pull
    lp.z = lp.z + (center.z - lp.z) / off * pull
  end
  lp.y = land.getHeight({ x = lp.x, y = lp.z })

  local playerName, dzName, dzRadius = info.playerName, dz.name, dz.radius or 300
  CIV.msgUnit(u, SKC.jumpers .. " jumpers away over " .. dzName ..
    "! Canopies in the air.", 10)
  CIV.schedule(function()
    local gname = CIV.spawnGround(lp, SKC.jumpers, C.templates.skydiver,
      C.fallbackTypes.skydiver, "CIVIL_SKYDIVE")
    local dist = math.floor(CIV.dist2D(lp, center) + 0.5)
    local quality = math.max(0, 1 - dist / math.max(100, dzRadius))
    CIV.Score.award(playerName, "skydive", quality, 0.5, 1,
      string.format("skydive drop (%d m from center)", dist))
    CIV.msgAll("SKYDIVE: the jumpers released by " .. playerName ..
      " landed " .. dist .. " m from the center of " .. dzName .. ".", 12)
    if gname then
      CIV.schedule(function() CIV.despawnGroup(gname) end, nil, SKC.despawnDelay)
    end
  end, nil, math.max(1, ffTime + canopyTime))
end

----------------------------------------------------------------------
-- MEDIA COVERAGE (passive)
----------------------------------------------------------------------

local CM = C.media
local filmTime = {}    -- unitName .. "|" .. eventKey -> seconds
local actionTime = {}  -- unitName .. "|" .. eventKey -> seconds with responders in frame
local aired = {}       -- eventKey -> true (one story per event)

-- active events worth filming: { key, point, label }. Every module lookup
-- is guarded, so leaving intervention files out of the load list is safe.
local function filmableEvents()
  local list = {}
  if CIV.Fire then
    for _, fire in pairs(CIV.Fire.actives()) do
      list[#list + 1] = { key = "fire" .. fire.id, point = fire.point,
        label = fire.kindDef.name .. " at " .. fire.pt.name }
    end
  end
  if CIV.Rescue then
    for _, sc in pairs(CIV.Rescue._scenarios) do
      for _, evt in pairs(sc.events) do
        list[#list + 1] = { key = sc.def.key .. evt.id, point = evt.point,
          label = sc.def.label .. " #" .. evt.id }
      end
    end
  end
  if CIV.SWAT then
    for _, scen in pairs(CIV.SWAT._scenarios) do
      list[#list + 1] = { key = "swat" .. scen.id, point = scen.pt.point,
        label = "SWAT operation at " .. scen.pt.name }
    end
  end
  if CIV.Police then
    for _, chase in pairs(CIV.Police._chases) do
      local g = Group.getByName(chase.gname)
      local u = g and g:getUnit(1)
      if u and u:isExist() then
        list[#list + 1] = { key = "chase" .. chase.id, point = u:getPoint(),
          label = "police chase #" .. chase.id }
      end
    end
  end
  return list
end

if CM.enabled then
  CIV.schedule(function(_, t)
    local events = filmableEvents()
    if #events > 0 then
      -- responders on scene, per event: player aircraft close to the
      -- action (the filmer checks against this list, excluding itself)
      local onScene = {}
      for _, evt in ipairs(events) do
        local names = {}
        CIV.forEachPlayer(function(a, ainfo)
          if ainfo.category ~= Unit.Category.HELICOPTER
             and ainfo.category ~= Unit.Category.AIRPLANE then return end
          if CIV.dist2D(a:getPoint(), evt.point) <= CM.actionRadius then
            names[ainfo.unitName] = true
          end
        end)
        onScene[evt.key] = names
      end
      -- helicopters AND airplanes: a trainer orbiting the ring films too
      CIV.forEachPlayer(function(u, info)
        if info.category ~= Unit.Category.HELICOPTER
           and info.category ~= Unit.Category.AIRPLANE then return end
        local p = u:getPoint()
        if CIV.agl(p) < CM.minAGL then return end
        for _, evt in ipairs(events) do
          if not aired[evt.key] then
            local d = CIV.dist2D(p, evt.point)
            if d >= CM.minDist and d <= CM.maxDist then
              local k = info.unitName .. "|" .. evt.key
              filmTime[k] = (filmTime[k] or 0) + 5
              -- ACTION FOOTAGE: another aircraft working the event while
              -- you film makes the story worth more
              for name in pairs(onScene[evt.key] or {}) do
                if name ~= info.unitName then
                  actionTime[k] = (actionTime[k] or 0) + 5
                  break
                end
              end
              if filmTime[k] >= CM.filmSeconds then
                aired[evt.key] = true
                local frac = math.min(1, (actionTime[k] or 0) / CM.filmSeconds)
                CIV.Score.award(info.playerName, "media", 0.7, 0.5,
                  1 + CM.actionBonus * frac,
                  string.format("live coverage: %s (action footage %d%%)",
                    evt.label, math.floor(frac * 100)))
                CIV.msgAll("LIVE ON AIR: " .. info.playerName ..
                  " broadcast footage of the " .. evt.label ..
                  (frac > 0.5 and " with the responders in frame." or "."), 15)
              end
            end
          end
        end
      end)
    end
    return t + 5
  end, nil, 20)
end

----------------------------------------------------------------------
-- TASK BOARD (pilot-called aviation tasks)
-- Recon, VIP and medical transfer are not pushed on the pilots anymore:
-- the director POSTS OFFERS and whoever is ready accepts one via F10
-- (maybe you are refueling, or mid-task: nothing gets assigned to you).
-- Offers pre-roll severity so the board shows the expected points, and
-- PRIORITY offers carry a score bonus. GM marker commands bypass the
-- board on purpose: the commander wants the event NOW. The MedEvac chain
-- also stays direct: that patient already exists and his clock is
-- ticking.
----------------------------------------------------------------------

CIV.TaskBoard = { _offers = {}, _oid = 0 }
local TB = CIV.TaskBoard
local CB = C.taskBoard

local offerKinds = {
  recon    = { label = "Recon anomaly", scoreKey = "recon",
               start = function(o) return RC.start({ severity = o.severity,
                 scoreBonus = o.bonus }) end },
  vip      = { label = "VIP shuttle", scoreKey = "vip",
               start = function(o) return VP.start({ severity = o.severity,
                 scoreBonus = o.bonus }) end },
  transfer = { label = "Medical transfer", scoreKey = "medTransfer",
               start = function(o) return MT.start({ severity = o.severity,
                 scoreBonus = o.bonus }) end },
}

local function offerCount()
  local n = 0
  for _ in pairs(TB._offers) do n = n + 1 end
  return n
end

function TB.post(kind)
  local k = offerKinds[kind]
  if not k then return nil end
  if not CB.enabled then
    -- board disabled in config: fall back to the old push behavior
    return k.start({ severity = nil, bonus = 1 })
  end
  if offerCount() >= CB.maxOffers then return nil end
  TB._oid = TB._oid + 1
  local offer = {
    id = TB._oid, kind = kind, label = k.label,
    severity = kind == "transfer"
      and CIV.rollSeverity({ min = C.medTransfer.minSeverity, max = 10 })
      or CIV.rollSeverity(),
    priority = math.random(100) <= CB.priorityChance,
    expiresAt = timer.getTime() + CB.offerTtl,
  }
  offer.bonus = offer.priority and CB.priorityBonus or 1
  offer.points = CIV.Score.compute(k.scoreKey, 0.8, 0.5,
    CIV.severityMult(offer.severity) * offer.bonus)
  TB._offers[offer.id] = offer
  CIV.msgAll("TASK BOARD: new " .. (offer.priority and "PRIORITY " or "") ..
    "offer: " .. offer.label .. ", severity " .. offer.severity ..
    "/10, about " .. offer.points .. " pts" ..
    (offer.priority and (" (includes the +" ..
      math.floor((CB.priorityBonus - 1) * 100) .. "% priority bonus)") or "") ..
    ".\nAccept it via F10 -> Aviation tasks -> Task board.", 15)
  return offer
end

local function sortedOffers()
  local list = {}
  for _, o in pairs(TB._offers) do list[#list + 1] = o end
  table.sort(list, function(a, b) return a.id < b.id end)
  return list
end

local function listOffers(gid)
  local list = sortedOffers()
  if #list == 0 then
    CIV.msgGroupId(gid, "The task board is empty.", 10)
    return
  end
  local txt = "TASK BOARD (accept by slot number):\n"
  for i, o in ipairs(list) do
    txt = txt .. string.format("%d. %s%s  severity %d/10  ~%d pts  %d min left\n",
      i, o.priority and "[PRIORITY] " or "", o.label, o.severity, o.points,
      math.max(0, math.floor((o.expiresAt - timer.getTime()) / 60)))
  end
  CIV.msgGroupId(gid, txt, 25)
end

function TB.accept(slot, uname)
  local u = Unit.getByName(uname)
  local offer = sortedOffers()[slot]
  if not offer then
    if u then CIV.msgUnit(u, "No offer in slot " .. slot ..
      ": check the board first.", 8) end
    return
  end
  TB._offers[offer.id] = nil
  local started = offerKinds[offer.kind].start(offer)
  local info = CIV.players[uname]
  if started then
    CIV.msgAll("TASK BOARD: '" .. offer.label .. "' accepted" ..
      (info and (" by " .. info.playerName) or "") .. ". Task is live.", 10)
  elseif u then
    CIV.msgUnit(u, "The offer could not start (missing zones or cap " ..
      "reached). It has been taken off the board.", 10)
  end
end

-- offer expiry
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for id, offer in pairs(TB._offers) do
    if now > offer.expiresAt then
      TB._offers[id] = nil
      CIV.log("Task board: offer '" .. offer.label .. "' expired unclaimed")
    end
  end
  return t + 30
end, nil, 30)

----------------------------------------------------------------------
-- F10 MENU + EVENT STARTERS
----------------------------------------------------------------------

CIV.Menu_register(function(gid, uname)
  local sub = missionCommands.addSubMenuForGroup(gid, "Aviation tasks", CIV.rootMenu[gid])
  missionCommands.addCommandForGroup(gid, "Recon: report anomaly overhead",
    sub, reportAnomaly, uname)
  missionCommands.addCommandForGroup(gid, "Skydive: release jumpers (over a drop zone)",
    sub, SK.release, uname)
  if CB.enabled then
    local board = missionCommands.addSubMenuForGroup(gid, "Task board", sub)
    missionCommands.addCommandForGroup(gid, "List offers", board, listOffers, gid)
    for slot = 1, math.min(CB.maxOffers, 6) do
      missionCommands.addCommandForGroup(gid, "Accept offer " .. slot, board,
        function() TB.accept(slot, uname) end)
    end
  end
  missionCommands.addCommandForGroup(gid, "Active aviation tasks", sub, function()
    local n, txt = 0, "Active aviation tasks:\n"
    for _, a in pairs(RC._anomalies) do
      n = n + 1
      txt = txt .. string.format("- Recon anomaly (severity %d/10), corridor, %d min left\n",
        a.severity, math.max(0, math.floor((a.expiresAt - timer.getTime()) / 60)))
    end
    for _, job in pairs(VP._jobs) do
      n = n + 1
      txt = txt .. string.format("- VIP %s -> %s (%s)\n", job.from.name,
        job.to.name, job.state)
    end
    for _, job in pairs(MT._jobs) do
      n = n + 1
      txt = txt .. string.format(
        "- Medical transfer %s -> %s (%s, %d min left)\n", job.from.name,
        job.to.name, job.state,
        math.max(0, math.floor((job.deadline - timer.getTime()) / 60)))
    end
    CIV.msgGroupId(gid, n > 0 and txt or "No active aviation tasks.", 20)
  end)
end)

-- the director and the admin menu post OFFERS on the board (pilot-called
-- tasks); with taskBoard.enabled = false TB.post falls back to direct starts
CIV.EventStarters.recon = { label = "Recon anomaly (board offer)",
  fn = function() return TB.post("recon") end }
CIV.EventStarters.vip = { label = "VIP shuttle (board offer)",
  fn = function() return TB.post("vip") end }
CIV.EventStarters.transfer = { label = "Medical transfer (board offer)",
  fn = function() return TB.post("transfer") end }

CIV.log("CivilAviation loaded")

-- ====================================================================
-- >>> Scripts/46_CivilAirTraffic.lua
-- ====================================================================
----------------------------------------------------------------------
-- DCS Civil Mission Template - Ambient air traffic
-- File: 46_CivilAirTraffic.lua  (requires 01_CivilCore.lua; load after
-- the other intervention files, before 50_CivilCommand.lua)
--
--   TRAFFIC: AI civil flights between the map airports, purely scenic
--   (the map feels alive). Flights spawn airborne a few km out of the
--   departure airdrome, cruise, and LAND at the destination, where they
--   are cleared after shutdown. Type and livery come from the optional
--   "CIVIL Airliner" template (Civil Aircraft Mod types work well),
--   fallback Yak-40. Hard cap on simultaneous flights.
--
--   RESTRICTED AREAS: sometimes a flight strays into a "CIVIL Restricted"
--   zone and loiters there. The violation is armed only if a player
--   airplane is airborne to answer it: intercept = fly within the
--   configured radius of the violator for the required seconds, then it
--   is escorted out and the interceptor is paid. If nobody intercepts in
--   time, ATC diverts the flight out by itself, no points for anyone.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config
local AT = C.airTraffic
local RS = AT.restricted

CIV.AirTraffic = { _flights = {}, _fid = 0 }
local AIR = CIV.AirTraffic

----------------------------------------------------------------------
-- AIRPORT LIST
----------------------------------------------------------------------

local airbaseCache
local function airports()
  if airbaseCache then return airbaseCache end
  airbaseCache = {}
  local ok, list = pcall(world.getAirbases)
  if not ok or type(list) ~= "table" then return airbaseCache end
  local exclude = {}
  for _, n in ipairs(AT.excludeAirports) do exclude[n] = true end
  local only = nil
  if #AT.airports > 0 then
    only = {}
    for _, n in ipairs(AT.airports) do only[n] = true end
  end
  local airdromeCat = (Airbase and Airbase.Category and Airbase.Category.AIRDROME) or 0
  for _, ab in ipairs(list) do
    local okAll, entry = pcall(function()
      return { name = ab:getName(), id = ab:getID(), point = ab:getPoint(),
               cat = ab:getDesc().category }
    end)
    if okAll and entry and entry.cat == airdromeCat
       and not exclude[entry.name] and (not only or only[entry.name]) then
      airbaseCache[#airbaseCache + 1] = entry
    end
  end
  CIV.log("Air traffic: " .. #airbaseCache .. " airdromes available")
  return airbaseCache
end

----------------------------------------------------------------------
-- FLIGHT SPAWN
----------------------------------------------------------------------

function AIR.count()
  local n = 0
  for _ in pairs(AIR._flights) do n = n + 1 end
  return n
end

-- type/livery from the CIVIL Airliner template pool (one picked at
-- random), fallback stock type otherwise
local function trafficType()
  local tpls = CIV.Templates.byPrefix(C.templates.airliner)
  if #tpls > 0 then
    local tpl = tpls[math.random(#tpls)]
    local unit = tpl.data.units and tpl.data.units[1]
    if unit and unit.type then return unit.type, unit.livery_id end
  end
  return C.fallbackTypes.airliner, nil
end

local function interceptorAirborne()
  local found = false
  CIV.forEachPlayer(function(u, info)
    if not found and info.category == Unit.Category.AIRPLANE and u:inAir() then
      found = true
    end
  end)
  return found
end

function AIR.spawn()
  if not AT.enabled then return nil end
  if AIR.count() >= AT.maxActive then return nil end
  local list = airports()
  if #list < 2 then return nil end

  local from, to
  for _ = 1, 15 do
    from = list[math.random(#list)]
    local cand = list[math.random(#list)]
    if cand.name ~= from.name
       and CIV.dist2D(from.point, cand.point) >= AT.minLegKm * 1000 then
      to = cand
      break
    end
  end
  if not to then return nil end

  -- sometimes the flight strays through a restricted zone; armed only if
  -- a player airplane is airborne to answer it (no interceptors, no task)
  local viaZone = nil
  if RS.enabled and math.random(100) <= RS.violationChance then
    local zones = CIV.Zones.byPrefix(C.zones.restricted)
    if #zones > 0 and (not RS.requirePlayers or interceptorAirborne()) then
      viaZone = zones[math.random(#zones)]
    end
  end

  AIR._fid = AIR._fid + 1
  local alt = CIV.randBetween(AT.altitude)
  local speed = CIV.randBetween(AT.speed)
  local typeName, livery = trafficType()
  local gname = CIV.uniqueName("CIVIL_TRAFFIC")
  local brg = CIV.bearingDeg(from.point,
    viaZone and { x = viaZone.center.x, z = viaZone.center.z } or to.point)
  local sp = CIV.offsetPoint(from.point, brg, 5000)
  local spAlt = CIV.groundY(sp) + math.max(600, alt * 0.4)

  local points = {
    { x = sp.x, y = sp.z, alt = spAlt, alt_type = "BARO",
      type = "Turning Point", action = "Turning Point", speed = speed },
  }
  if viaZone then
    points[#points + 1] = { x = viaZone.center.x, y = viaZone.center.z,
      alt = alt, alt_type = "BARO", type = "Turning Point",
      action = "Turning Point", speed = speed }
  end
  points[#points + 1] = { x = to.point.x, y = to.point.z, alt = alt,
    alt_type = "BARO", type = "Land", action = "Landing", speed = speed,
    airdromeId = to.id }

  local ok = pcall(coalition.addGroup, C.countryId, Group.Category.AIRPLANE, {
    visible = false, lateActivation = false, task = "Nothing",
    name = gname, groupId = CIV.newGroupId(), communication = false,
    units = { {
      type = typeName, name = gname .. "_1", unitId = CIV.newUnitId(),
      x = sp.x, y = sp.z, alt = spAlt, alt_type = "BARO", speed = speed,
      heading = math.rad(brg), skill = "Excellent", livery_id = livery,
      payload = { pylons = {}, fuel = 3000, flare = 0, chaff = 0, gun = 0 },
    } },
    route = { points = points },
  })
  if not ok then
    CIV.log("Air traffic: spawn failed for type " .. tostring(typeName))
    return nil
  end

  local flight = {
    id = AIR._fid, gname = gname, from = from, to = to,
    viaZone = viaZone, violationActive = false, resolved = false,
    interceptTime = {}, spawnedAt = timer.getTime(),
  }
  AIR._flights[flight.id] = flight
  CIV.log("Air traffic: flight #" .. flight.id .. " " .. from.name ..
    " -> " .. to.name .. (viaZone and " (VIOLATOR)" or ""))
  return flight
end

local function flightUnit(flight)
  local g = Group.getByName(flight.gname)
  local u = g and g:getUnit(1)
  if u and u:isExist() then return u end
  return nil
end

local function removeFlight(flight, despawnAfter)
  AIR._flights[flight.id] = nil
  CIV.unmark(flight.zoneMarkId)
  local gname = flight.gname
  CIV.schedule(function() CIV.despawnGroup(gname) end, nil, despawnAfter or 1)
end

-- resume the flight plan to the destination (after intercept or divert)
local function resumeToDestination(flight, fromP, speed)
  local g = Group.getByName(flight.gname)
  if not g then return end
  pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = {
      { x = fromP.x, y = fromP.z, alt = fromP.y, alt_type = "BARO",
        type = "Turning Point", action = "Turning Point", speed = speed },
      { x = flight.to.point.x, y = flight.to.point.z, alt = fromP.y,
        alt_type = "BARO", type = "Land", action = "Landing", speed = speed,
        airdromeId = flight.to.id },
    } } } })
  end)
end

-- violators loiter: keep steering them back onto the zone center until
-- the violation is resolved (intercept or self-divert)
local function loiterInZone(flight, fromP, speed)
  local g = Group.getByName(flight.gname)
  if not g then return end
  pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = {
      { x = fromP.x, y = fromP.z, alt = fromP.y, alt_type = "BARO",
        type = "Turning Point", action = "Turning Point", speed = speed },
      { x = flight.viaZone.center.x, y = flight.viaZone.center.z,
        alt = fromP.y, alt_type = "BARO", type = "Turning Point",
        action = "Turning Point", speed = speed },
    } } } })
  end)
end

----------------------------------------------------------------------
-- TRAFFIC + VIOLATION LOOP
----------------------------------------------------------------------

local nextAirSpawn = timer.getTime() + CIV.randBetween(AT.spawnEvery)
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, flight in pairs(AIR._flights) do
    local u = flightUnit(flight)
    if not u then
      removeFlight(flight, 1)
    elseif now - flight.spawnedAt > AT.maxLifetime then
      removeFlight(flight, 1)      -- hard cleanup for stragglers
    else
      local p = u:getPoint()

      -- arrival: landed near the destination -> cleared after shutdown
      if not u:inAir() and CIV.speed(u:getVelocity()) < 2
         and CIV.dist2D(p, flight.to.point) < 8000 then
        removeFlight(flight, 120)

      -- violation lifecycle
      elseif flight.viaZone and not flight.resolved then
        if not flight.violationActive then
          if CIV.Zones.contains(flight.viaZone, p) then
            flight.violationActive = true
            flight.violatedAt = now
            flight.nextLoiterKick = 0
            flight.zoneMarkId = CIV.drawEventZone(flight.viaZone,
              "RESTRICTED - unauthorized traffic", "restricted")
            CIV.msgAll("AIRSPACE ALERT: unidentified civil traffic entered " ..
              "the restricted area " .. flight.viaZone.name ..
              " and is loitering.\nMilitary flights: intercept and identify " ..
              "(fly within " .. RS.intercept.radius .. " m of it for " ..
              RS.intercept.seconds .. " seconds).", 25)
          end
        else
          -- keep the violator loitering inside the zone
          if now >= (flight.nextLoiterKick or 0) then
            flight.nextLoiterKick = now + 60
            loiterInZone(flight, p, CIV.randBetween(AT.speed) * 0.8)
          end
          -- intercept check
          local caught = nil
          CIV.forEachPlayer(function(a, info)
            if caught or info.category ~= Unit.Category.AIRPLANE then return end
            if not a:inAir() then return end
            if CIV.dist2D(a:getPoint(), p) <= RS.intercept.radius then
              flight.interceptTime[info.unitName] =
                (flight.interceptTime[info.unitName] or 0) + 10
              if flight.interceptTime[info.unitName] >= RS.intercept.seconds then
                caught = info
              end
            end
          end)
          if caught then
            flight.resolved = true
            CIV.unmark(flight.zoneMarkId)
            flight.zoneMarkId = nil
            CIV.Score.award(caught.playerName, "intercept", 0.9, 0.5, 1,
              "restricted-area intercept")
            CIV.msgAll("INTERCEPT: " .. caught.playerName ..
              " identified the violator and is escorting it out of " ..
              flight.viaZone.name .. ". Traffic resuming its flight plan.", 15)
            resumeToDestination(flight, p, CIV.randBetween(AT.speed))
          elseif now - flight.violatedAt > RS.divertAfter then
            flight.resolved = true
            CIV.unmark(flight.zoneMarkId)
            flight.zoneMarkId = nil
            CIV.msgAll("AIRSPACE ALERT: ATC diverted the unauthorized " ..
              "traffic out of " .. flight.viaZone.name ..
              " (no interceptor on it). Alert over.", 15)
            resumeToDestination(flight, p, CIV.randBetween(AT.speed))
          end
        end
      end
    end
  end
  if AT.enabled and now >= nextAirSpawn then
    AIR.spawn()
    nextAirSpawn = now + CIV.randBetween(AT.spawnEvery)
  end
  return t + 10
end, nil, 30)

CIV.EventStarters.traffic = { label = "Civil traffic flight",
  fn = function() return AIR.spawn() end }

CIV.log("CivilAirTraffic loaded")

-- ====================================================================
-- >>> Scripts/47_CivilSeaOps.lua
-- ====================================================================
----------------------------------------------------------------------
-- DCS Civil Mission Template - Sea operations
-- File: 47_CivilSeaOps.lua  (requires 01_CivilCore.lua; load after the
-- other intervention files, before 50_CivilCommand.lua)
--
--   SEA TRAFFIC: merchant ships spawn at a random point inside a
--   "CIVIL Sea Spawn" zone (staggered: two ships on the same spot
--   explode), sail a route over the "CIVIL Sea Lane" waypoint pool
--   (local random walk, same pattern as the police chase) and end in a
--   "CIVIL Sea Despawn" zone, where they are cleared. Purely scenic on
--   its own, and the target pool for the coast guard tasks.
--
--   COAST GUARD: helicopter inspection task. Fly alongside the reported
--   merchant (low, slow, close) to check the manifest. A clean manifest
--   pays a partial score; SUSPICIOUS cargo escalates: the ship runs for
--   it, the helicopter keeps track of it until the patrol boat arrives
--   and boards. Full score to the inspecting pilot on the boarding.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config
local ST = C.seaOps.traffic
local CG = C.seaOps.coastGuard

----------------------------------------------------------------------
-- SEA TRAFFIC
----------------------------------------------------------------------

CIV.SeaTraffic = { _ships = {}, _sid = 0 }
local SEA = CIV.SeaTraffic

local function zonesReady()
  return #CIV.Zones.byPrefix(C.zones.seaSpawn) > 0
     and #CIV.Zones.byPrefix(C.zones.seaDespawn) > 0
end

function SEA.count()
  local n = 0
  for _ in pairs(SEA._ships) do n = n + 1 end
  return n
end

local function shipUnit(ship)
  local g = Group.getByName(ship.gname)
  local u = g and g:getUnit(1)
  if u and u:isExist() then return u end
  return nil
end

-- random point inside a zone, kept clear of the other active ships
local function randomPointIn(area, minGap)
  for _ = 1, 12 do
    local ang = math.random() * 2 * math.pi
    local r = math.sqrt(math.random()) * math.max(200, (area.radius or 400) * 0.8)
    local p = { x = area.center.x + math.cos(ang) * r,
                z = area.center.z + math.sin(ang) * r }
    local clear = true
    for _, ship in pairs(SEA._ships) do
      local u = shipUnit(ship)
      if u and CIV.dist2D(u:getPoint(), p) < minGap then clear = false break end
    end
    if clear then return p end
  end
  return nil
end

-- Route: from the lane point nearest the spawn, walk laneHops nearby lane
-- points (local random walk over the CIVIL Sea Lane pool), then head for
-- the despawn zone nearest the last hop. No lanes defined = straight to
-- the despawn zone.
local function buildRoute(fromP)
  local hops = {}
  local lanes = CIV.Pool.load(C.zones.seaLane)
  if #lanes > 0 then
    local current, bestDist = nil, 1e12
    for _, pt in ipairs(lanes) do
      local d = CIV.dist2D(pt.point, fromP)
      if d < bestDist then current, bestDist = pt, d end
    end
    local lastName = nil
    while current and #hops < ST.laneHops do
      hops[#hops + 1] = current
      local nearby = CIV.Pool.near(C.zones.seaLane, current.point,
        ST.neighborRadius, lastName)
      lastName = current.name
      current = #nearby > 0 and nearby[math.random(#nearby)] or nil
    end
  end
  local lastP = #hops > 0 and hops[#hops].point or fromP
  local dz = CIV.Zones.nearest(C.zones.seaDespawn, lastP)
  return hops, dz
end

-- (re)assign the sailing route from an arbitrary start point
local function routeShip(ship, fromP, speed)
  local g = Group.getByName(ship.gname)
  if not g then return end
  local points = { { x = fromP.x, y = fromP.z, type = "Turning Point", speed = speed } }
  for _, hop in ipairs(ship.remainingHops or ship.hops) do
    points[#points + 1] = { x = hop.point.x, y = hop.point.z,
                            type = "Turning Point", speed = speed }
  end
  points[#points + 1] = { x = ship.endP.x, y = ship.endP.z,
                          type = "Turning Point", speed = speed }
  pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = points } } })
  end)
end

function SEA.spawn()
  if not ST.enabled or not zonesReady() then return nil end
  if SEA.count() >= ST.maxActive then return nil end
  local areas = CIV.Zones.byPrefix(C.zones.seaSpawn)
  local area = areas[math.random(#areas)]
  local p = randomPointIn(area, ST.minSpawnGap)
  if not p then return nil end
  local hops, dzArea = buildRoute(p)
  if not dzArea then return nil end

  SEA._sid = SEA._sid + 1
  local gname = CIV.spawnBoat({ x = p.x, y = 0, z = p.z }, "CIVIL_MERCHANT",
    C.templates.merchant, C.fallbackTypes.merchant)
  local ship = {
    id = SEA._sid, gname = gname, hops = hops,
    endP = { x = dzArea.center.x, z = dzArea.center.z },
    speed = ST.speed, spawnedAt = timer.getTime(), inspection = nil,
  }
  SEA._ships[ship.id] = ship
  CIV.schedule(function() routeShip(ship, p, ship.speed) end, nil, 2)
  CIV.log("Sea traffic: merchant #" .. ship.id .. " sailing out of " .. area.name)
  return ship
end

local function removeShip(ship, despawnAfter)
  SEA._ships[ship.id] = nil
  local gname = ship.gname
  CIV.schedule(function() CIV.despawnGroup(gname) end, nil, despawnAfter or 1)
end

-- traffic loop: arrivals, hard cleanup, spawn cadence
local nextSeaSpawn = timer.getTime() + CIV.randBetween(ST.spawnEvery)
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, ship in pairs(SEA._ships) do
    local u = shipUnit(ship)
    if not u then
      SEA._ships[ship.id] = nil
    elseif CIV.dist2D(u:getPoint(), ship.endP) <= ST.arriveRadius
        or now - ship.spawnedAt > ST.maxLifetime then
      if ship.inspection and CIV.CoastGuard then
        CIV.CoastGuard.shipGone(ship.inspection)
      end
      removeShip(ship, 5)
    end
  end
  if ST.enabled and now >= nextSeaSpawn then
    SEA.spawn()
    nextSeaSpawn = now + CIV.randBetween(ST.spawnEvery)
  end
  return t + 20
end, nil, 20)

----------------------------------------------------------------------
-- COAST GUARD
----------------------------------------------------------------------

CIV.CoastGuard = { _tasks = {}, _tid = 0 }
local CGD = CIV.CoastGuard

-- opts (command center): { point = vec3 (targets the merchant nearest the
--                          marker), severity = 1..10 }
function CGD.start(opts)
  if not CG.enabled then return nil end
  local candidates = {}
  for _, ship in pairs(SEA._ships) do
    if not ship.inspection then
      local u = shipUnit(ship)
      if u then candidates[#candidates + 1] = { ship = ship, unit = u } end
    end
  end
  if #candidates == 0 then return nil end

  local pick
  if opts and opts.point then
    local bestDist = 1e12
    for _, cand in ipairs(candidates) do
      local d = CIV.dist2D(cand.unit:getPoint(), opts.point)
      if d < bestDist then pick, bestDist = cand, d end
    end
  else
    pick = candidates[math.random(#candidates)]
  end

  CGD._tid = CGD._tid + 1
  local task = {
    id = CGD._tid, ship = pick.ship, state = "inspect",
    severity = (opts and opts.severity)
      and math.max(1, math.min(10, opts.severity))
      or CIV.rollSeverity(CG.severity),
    inspectTime = {},        -- unitName -> seconds alongside
    startedAt = timer.getTime(),
  }
  pick.ship.inspection = task.id
  CGD._tasks[task.id] = task
  local p = pick.unit:getPoint()
  CIV.msgAll("COAST GUARD (severity " .. task.severity .. "/10): inspect " ..
    "the merchant vessel M/V " .. (100 + task.id) ..
    ", last reported at:\n" .. CIV.coordText(p) ..
    "\nFly alongside LOW and SLOW (within " .. CG.inspect.radius ..
    " m, below " .. CG.inspect.maxRelAlt .. " m over the deck) for " ..
    CG.inspect.seconds .. " seconds to check the manifest.", 25)
  CIV.log("Coast guard task #" .. task.id .. " on merchant #" .. pick.ship.id)
  return task
end

local function closeTask(task)
  if task.ship then task.ship.inspection = nil end
  if task.boatGname then
    local gname = task.boatGname
    CIV.schedule(function() CIV.despawnGroup(gname) end, nil, 120)
  end
  CGD._tasks[task.id] = nil
end

-- command center: close a task without any outcome
function CGD.cancel(task)
  if not CGD._tasks[task.id] then return false end
  closeTask(task)
  return true
end

-- the merchant under inspection vanished (arrived or was cleaned up)
function CGD.shipGone(taskId)
  local task = CGD._tasks[taskId]
  if not task then return end
  CIV.msgAll("COAST GUARD: the merchant left the patrol sector. Task over.", 12)
  closeTask(task)
end

-- patrol boat dispatch: launched from the nearest CIVIL Vessel Spawn
-- harbor, re-tasked toward the (moving) suspect every pursuit tick
local function dispatchPatrolBoat(task, targetP)
  local best, bestDist = nil, 1e12
  for _, pt in ipairs(CIV.Pool.load(C.zones.vesselSpawn)) do
    local d = CIV.dist2D(pt.point, targetP)
    if d < bestDist then best, bestDist = pt, d end
  end
  if not best then return end
  task.boatGname = CIV.spawnBoat(best.point, "CIVIL_PATROL",
    C.templates.vessel, C.fallbackTypes.rescueBoat)
  CIV.msgAll("COAST GUARD: patrol boat launched from " .. best.name ..
    ", keep track of the suspect until it arrives.", 12)
end

local function steerBoat(task, targetP)
  if not task.boatGname then return end
  local g = Group.getByName(task.boatGname)
  if not g then return end
  pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = {
      { x = targetP.x, y = targetP.z, type = "Turning Point",
        speed = C.rescue.vessels.speed },
    } } } })
  end)
end

-- suspect ships stop following the lanes and run straight for the exit
local function shipFlees(task, fromP)
  task.ship.remainingHops = {}
  task.ship.speed = CG.fleeSpeed
  routeShip(task.ship, { x = fromP.x, z = fromP.z }, CG.fleeSpeed)
end

-- inspection / pursuit loop (2 s tick)
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, task in pairs(CGD._tasks) do
    local u = shipUnit(task.ship)
    if not u then
      CGD.shipGone(task.id)
    else
      local sp = u:getPoint()
      if task.state == "inspect" then
        CIV.forEachPlayerHelo(function(h, info)
          if task.state ~= "inspect" then return end
          local hp = h:getPoint()
          local relAlt = hp.y - sp.y
          local relOk = relAlt >= 0 and relAlt <= CG.inspect.maxRelAlt
          local hv, sv = h:getVelocity(), u:getVelocity()
          local relSpeed = CIV.speed({ x = hv.x - sv.x, y = hv.y - sv.y,
                                       z = hv.z - sv.z })
          if CIV.dist2D(hp, sp) <= CG.inspect.radius and relOk
             and relSpeed <= CG.inspect.maxRelSpeed then
            task.inspectTime[info.unitName] =
              (task.inspectTime[info.unitName] or 0) + 2
            if task.inspectTime[info.unitName] >= CG.inspect.seconds then
              task.inspector = info.playerName
              if math.random(100) <= CG.suspectChance then
                task.state = "pursuit"
                task.lastContact = now
                CIV.msgAll("COAST GUARD: " .. info.playerName ..
                  " reports SUSPICIOUS CARGO on deck. The vessel is " ..
                  "running: keep track of it (within " ..
                  math.floor(CG.track.radius / 1000) ..
                  " km) until the patrol boat boards it.", 20)
                shipFlees(task, sp)
                dispatchPatrolBoat(task, sp)
              else
                CIV.msgAll("COAST GUARD: manifest of the inspected vessel " ..
                  "is CLEAN. Good check, " .. info.playerName .. ".", 15)
                CIV.Score.award(info.playerName, "coastGuard", 0.6, 0.5,
                  CIV.severityMult(task.severity), "vessel inspection (clean)")
                closeTask(task)
              end
            end
          end
        end)
      elseif task.state == "pursuit" then
        -- helicopter must keep contact
        local contact = false
        CIV.forEachPlayerHelo(function(h)
          if not contact
             and CIV.dist2D(h:getPoint(), sp) <= CG.track.radius then
            contact = true
          end
        end)
        if contact then task.lastContact = now end
        if now - task.lastContact > CG.track.graceSeconds then
          CIV.msgAll("COAST GUARD: contact lost too long, the suspect " ..
            "slipped away. Task failed.", 15)
          closeTask(task)
        else
          -- steer the patrol boat onto the moving target
          task.nextSteer = task.nextSteer or 0
          if now >= task.nextSteer then
            task.nextSteer = now + 30
            steerBoat(task, sp)
          end
          -- boarding check
          if task.boatGname then
            local bg = Group.getByName(task.boatGname)
            local bu = bg and bg:getUnit(1)
            if bu and bu:isExist()
               and CIV.dist2D(bu:getPoint(), sp) <= CG.boatHold.radius then
              task.boardTime = (task.boardTime or 0) + 2
              if task.boardTime >= CG.boatHold.seconds then
                CIV.msgAll("COAST GUARD: suspect vessel BOARDED. Cargo " ..
                  "seized. Textbook work by " ..
                  (task.inspector or "the patrol") .. ".", 20)
                if task.inspector then
                  CIV.Score.award(task.inspector, "coastGuard", 1.0, 0.5,
                    CIV.severityMult(task.severity),
                    "vessel inspection (suspect boarded)")
                end
                -- the merchant heaves to under escort, then clears out
                pcall(function()
                  local g = Group.getByName(task.ship.gname)
                  if g then g:getController():setTask({ id = "Hold", params = {} }) end
                end)
                local ship = task.ship
                CIV.schedule(function() removeShip(ship, 1) end, nil, 300)
                closeTask(task)
              end
            else
              task.boardTime = nil
            end
          end
        end
      end
    end
  end
  return t + 2
end, nil, 25)

CIV.EventStarters.inspection = { label = "Coast guard inspection",
  fn = function() return CGD.start() end }
CIV.EventStarters.merchant = { label = "Merchant ship (sea traffic)",
  fn = function() return SEA.spawn() end }

CIV.Menu_register(function(gid)
  local sub = missionCommands.addSubMenuForGroup(gid, "Coast guard", CIV.rootMenu[gid])
  missionCommands.addCommandForGroup(gid, "Active sea tasks", sub, function()
    local n, txt = 0, "Active sea tasks:\n"
    for _, task in pairs(CGD._tasks) do
      n = n + 1
      local u = shipUnit(task.ship)
      txt = txt .. string.format("- Inspection M/V %d (severity %d/10, %s)%s\n",
        100 + task.id, task.severity, task.state,
        u and ("  " .. CIV.llString(u:getPoint())) or "")
    end
    txt = txt .. string.format("Merchant traffic: %d ship(s) at sea.", SEA.count())
    CIV.msgGroupId(gid, n > 0 and txt
      or ("No inspection tasks. Merchant traffic: " .. SEA.count() .. " ship(s) at sea."), 20)
  end)
end)

CIV.log("CivilSeaOps loaded")

